#[derive(Debug, Clone, PartialEq, Eq, Hash, serde::Deserialize, serde::Serialize)]
pub enum MirType {
    Void,
    Int(IntWidth),
    Float(FloatWidth),
    Bool,
    /// Native String type with the following contract:
    ///
    /// # Representation
    /// - Uses `{ptr, len}` structure: pointer to bytes + length in bytes
    /// - Pointer is `*const u8` to UTF-8 encoded bytes
    /// - Length is `usize` byte count (NOT character count)
    ///
    /// # Semantics
    /// - **Immutable**: Cannot be mutated after creation
    /// - **Owned**: Compiler-managed cleanup via Phase 1 ownership
    /// - **UTF-8**: All strings are valid UTF-8 encoded
    ///
    /// # Operations
    /// - **Equality**: Content-based (memcmp), NOT pointer identity
    /// - **Length**: Always honors explicit length, no C-string assumptions
    /// - **No null-termination**: Length-prefix, not null-terminated
    ///
    /// # FFI Boundary
    /// - When crossing FFI: marshalled as `{ptr: *const u8, len: usize}`
    /// - Returned via buffer: writes bytes + null terminator, returns length as i32
    /// - Never uses C-string APIs (strcpy, strlen, puts, etc.)
    ///
    /// # Implementation Notes
    /// - All runtime operations MUST use length, never assume null-termination
    /// - When generating LLVM IR: use `[i8 x len]` array type
    /// - When comparing: use `memcmp` or equivalent, not pointer equality
    String,
    Struct(String, Vec<MirType>),
    Unit,
    RawPtr,
    Option(Box<MirType>),
    Result {
        ok: Box<MirType>,
        err: Box<MirType>,
    },
    /// Tuple type: grouped value paths, NOT aggregate shells.
    /// No shell cleanup, no recursive cleanup, no struct-like treatment.
    Tuple(Vec<MirType>),
    Enum {
        name: String,
        variants: Vec<MirEnumVariant>,
    },
    List(Box<MirType>),
}

