impl fmt::Display for MirType {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            MirType::Void => write!(f, "void"),
            MirType::Int(w) => write!(f, "{w}"),
            MirType::Float(w) => write!(f, "{w}"),
            MirType::Bool => write!(f, "bool"),
            MirType::String => write!(f, "String"),
            MirType::Struct(name, args) => {
                write!(f, "{name}")?;
                if !args.is_empty() {
                    write!(f, "<")?;
                    for (i, arg) in args.iter().enumerate() {
                        if i > 0 {
                            write!(f, ", ")?;
                        }
                        write!(f, "{arg}")?;
                    }
                    write!(f, ">")?;
                }
                Ok(())
            }
            MirType::Unit => write!(f, "()"),
            MirType::RawPtr => write!(f, "rawptr"),
            MirType::Option(inner) => write!(f, "?{inner}"),
            MirType::Result { ok, .. } => write!(f, "!{ok}"),
            MirType::Tuple(elems) => {
                write!(f, "(")?;
                for (i, elem) in elems.iter().enumerate() {
                    if i > 0 {
                        write!(f, ", ")?;
                    }
                    write!(f, "{elem}")?;
                }
                write!(f, ")")
            }
            MirType::Enum { name, .. } => write!(f, "{name}"),
            MirType::List(inner) => write!(f, "List<{inner}>"),
        }
    }
}

impl fmt::Display for IntWidth {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            IntWidth::I8 => write!(f, "i8"),
            IntWidth::I16 => write!(f, "i16"),
            IntWidth::I32 => write!(f, "i32"),
            IntWidth::I64 => write!(f, "i64"),
            IntWidth::U8 => write!(f, "u8"),
            IntWidth::U16 => write!(f, "u16"),
            IntWidth::U32 => write!(f, "u32"),
            IntWidth::U64 => write!(f, "u64"),
        }
    }
}

impl fmt::Display for FloatWidth {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            FloatWidth::F32 => write!(f, "f32"),
            FloatWidth::F64 => write!(f, "f64"),
        }
    }
}


