// ---- debug format helpers ----
fn format_type(ty: &MirType) -> String {
    match ty {
        MirType::Void => "void".to_string(),
        MirType::Int(w) => match w {
            IntWidth::I8 => "i8",
            IntWidth::I16 => "i16",
            IntWidth::I32 => "i32",
            IntWidth::I64 => "i64",
            IntWidth::U8 => "u8",
            IntWidth::U16 => "u16",
            IntWidth::U32 => "u32",
            IntWidth::U64 => "u64",
        }
        .to_string(),
        MirType::Float(w) => match w {
            FloatWidth::F32 => "f32",
            FloatWidth::F64 => "f64",
        }
        .to_string(),
        MirType::Bool => "i1".to_string(),
        MirType::String => "%String".to_string(),
        MirType::Struct(name, args) => {
            if args.is_empty() {
                format!("%{name}")
            } else {
                let type_args: Vec<String> = args.iter().map(format_type).collect();
                format!("%{}<{}>", name, type_args.join(", "))
            }
        }
        MirType::Unit => "void".to_string(),
        MirType::RawPtr => "rawptr".to_string(),
        MirType::Option(inner) => format!("?{}", format_type(inner)),
        MirType::Result { ok, err: _ } => format!("!{}", format_type(ok)),
        MirType::Tuple(elems) => {
            let inner: Vec<String> = elems.iter().map(format_type).collect();
            format!("({})", inner.join(", "))
        }
        MirType::Enum { name, .. } => format!("enum<{name}>"),
        MirType::List(inner) => format!("list<{}>", format_type(inner)),
    }
}

fn format_value(val: &MirValue) -> String {
    match val {
        MirValue::Int { value: n, .. } => n.to_string(),
        MirValue::Float(n) => format!("{n}"),
        MirValue::Bool(b) => if *b { "true" } else { "false" }.to_string(),
        MirValue::String(s) => format!("\"{s}\""),
        MirValue::Unit => "()".to_string(),
    }
}

fn format_expr(expr: &MirExpr) -> String {
    match expr {
        MirExpr::Local(id) => format!("%local_{}", id.0),
        MirExpr::Const(val) => format_value(val),
        MirExpr::BinOp { op, left, right } => {
            format!(
                "{} {} {}",
                format_expr(left),
                format_binop(op),
                format_expr(right)
            )
        }
        MirExpr::UnOp { op, operand } => {
            format!("{}{}", format_unop(op), format_expr(operand))
        }
        MirExpr::Call { target, args, .. } => {
            let args_str: Vec<String> = args.iter().map(format_expr).collect();
            let func_name = match target {
                MirCallTarget::Builtin { name } => name.as_str(),
                MirCallTarget::ModuleEntry { module_path, entry } => {
                    return format!("{}::{}({})", module_path, entry, args_str.join(", "));
                }
                MirCallTarget::Foreign { symbol, .. } => symbol.as_str(),
            };
            format!("{}({})", func_name, args_str.join(", "))
        }
        MirExpr::LoadStructField { source, field, .. } => {
            format!("{}.{}", format_expr(&MirExpr::Local(*source)), field)
        }
        MirExpr::Tuple(ids) => {
            let elems: Vec<String> = ids
                .iter()
                .map(|id| format_expr(&MirExpr::Local(*id)))
                .collect();
            format!("({})", elems.join(", "))
        }
        MirExpr::LoadListLen { source } => format!("len(%local_{})", source.0),
        MirExpr::LoadListIndex { source, index, .. } => {
            format!("%local_{}[{}]", source.0, format_expr(index))
        }
    }
}

fn format_binop(op: &MirBinOp) -> &'static str {
    match op {
        MirBinOp::Add => "+",
        MirBinOp::Sub => "-",
        MirBinOp::Mul => "*",
        MirBinOp::Div => "/",
        MirBinOp::Mod => "%",
        MirBinOp::Eq => "==",
        MirBinOp::Ne => "!=",
        MirBinOp::Lt => "<",
        MirBinOp::Gt => ">",
        MirBinOp::Le => "<=",
        MirBinOp::Ge => ">=",
        MirBinOp::And => "&&",
        MirBinOp::Or => "||",
    }
}

fn format_unop(op: &MirUnOp) -> &'static str {
    match op {
        MirUnOp::Neg => "-",
        MirUnOp::Not => "!",
    }
}

fn format_stmt(stmt: &MirStmt) -> String {
    match stmt {
        MirStmt::Assign { target, value } => {
            format!("%local_{} = {}", target.0, format_expr(value))
        }
        MirStmt::Call {
            target,
            callee,
            args,
        } => {
            let args_str: Vec<String> = args.iter().map(format_expr).collect();
            let func_name = match callee {
                MirCallTarget::Builtin { name } => name.as_str(),
                MirCallTarget::ModuleEntry { module_path, entry } => {
                    return format!("{}::{}({})", module_path, entry, args_str.join(", "));
                }
                MirCallTarget::Foreign { symbol, .. } => symbol.as_str(),
            };
            let call = format!("{}({})", func_name, args_str.join(", "));
            match target {
                Some(id) => format!("%local_{} = {}", id.0, call),
                None => call,
            }
        }
        MirStmt::ConstructOptionSome { target, value, ty } => {
            format!(
                "%local_{} = construct_option_some({}, {})",
                target.0,
                format_expr(value),
                format_type(ty)
            )
        }
        MirStmt::ConstructOptionNone { target, ty } => {
            format!(
                "%local_{} = construct_option_none({})",
                target.0,
                format_type(ty)
            )
        }
        MirStmt::ConstructResultOk { target, value, ty } => {
            format!(
                "%local_{} = construct_result_ok({}, {})",
                target.0,
                format_expr(value),
                format_type(ty)
            )
        }
        MirStmt::ConstructResultErr { target, value, ty } => {
            format!(
                "%local_{} = construct_result_err({}, {})",
                target.0,
                format_expr(value),
                format_type(ty)
            )
        }
        MirStmt::InspectOption {
            value,
            some_target,
            none_target,
        } => {
            format!(
                "inspect_option %local_{} -> {}:{}",
                value.0, some_target.0, none_target.0
            )
        }
        MirStmt::InspectResult {
            value,
            ok_target,
            err_target,
        } => {
            format!(
                "inspect_result %local_{} -> {}:{}",
                value.0, ok_target.0, err_target.0
            )
        }
        MirStmt::ExtractResultOk { source, target } => {
            format!(
                "%local_{} = extract_result_ok(%local_{})",
                target.0, source.0
            )
        }
        MirStmt::ExtractResultErr { source, target } => {
            format!(
                "%local_{} = extract_result_err(%local_{})",
                target.0, source.0
            )
        }
        MirStmt::ExtractOptionSome { source, target } => {
            format!(
                "%local_{} = extract_option_some(%local_{})",
                target.0, source.0
            )
        }
        MirStmt::ConstructStruct {
            target,
            name,
            fields,
        } => {
            let fields_str: Vec<String> = fields
                .iter()
                .map(|(f, v)| format!("{}: {}", f, format_expr(v)))
                .collect();
            format!(
                "%local_{} = construct_struct {}({})",
                target.0,
                name,
                fields_str.join(", ")
            )
        }
        MirStmt::StoreStructField {
            target,
            field,
            value,
        } => {
            format!(
                "store_struct_field %local_{}.{} = {}",
                target.0,
                field,
                format_expr(value)
            )
        }
        MirStmt::CleanupAggregateShell {
            local,
            struct_name,
            field_modes,
        } => {
            let modes_str: Vec<String> = field_modes
                .iter()
                .map(|m| match m {
                    FieldValueMode::InlineOwned => "owned".to_string(),
                    FieldValueMode::PointerToOwner(id) => format!("ptr->{}", id.0),
                })
                .collect();
            format!(
                "cleanup_aggregate_shell %local_{} (struct {}, modes: [{}])",
                local.0,
                struct_name,
                modes_str.join(", ")
            )
        }
        MirStmt::DestructureTuple { source, targets } => {
            let targets_str: Vec<String> =
                targets.iter().map(|t| format!("%local_{}", t.0)).collect();
            format!(
                "destructure_tuple {} -> ({})",
                format_expr(&MirExpr::Local(*source)),
                targets_str.join(", ")
            )
        }
        _ => "unsupported_stmt".to_string(),
    }
}

fn format_terminator(term: &MirTerminator) -> String {
    match term {
        MirTerminator::Return(val) => match val {
            Some(expr) => format!("return {}", format_expr(expr)),
            None => "return".to_string(),
        },
        MirTerminator::Goto(label) => format!("goto {label}"),
        MirTerminator::Branch {
            cond,
            then_block,
            else_block,
        } => format!(
            "branch {} ? {} : {}",
            format_expr(cond),
            then_block,
            else_block
        ),
        MirTerminator::Unreachable => "unreachable".to_string(),
    }
}
// ---- LLVM lowering (migration snapshot body) ----
fn is_expr_owned(
    expr: &MirExpr,
    owned_locals: &HashSet<u32>,
    string_literal_locals: &HashSet<u32>,
) -> bool {
    match expr {
        MirExpr::Local(id) => {
            owned_locals.contains(&id.0) && !string_literal_locals.contains(&id.0)
        }
        _ => false,
    }
}

struct ForeignFuncs {
    return_types: HashMap<String, MirType>,
    param_types: HashMap<String, Vec<MirType>>,
    sources: HashMap<String, ForeignSource>,
}

impl ForeignFuncs {
    fn from_module(externals: &[MirExternalFunc]) -> Self {
        let mut return_types = HashMap::new();
        let mut param_types = HashMap::new();
        let mut sources = HashMap::new();
        for ext in externals {
            if let MirCallTarget::Foreign { symbol, .. } = &ext.target {
                return_types.insert(symbol.clone(), ext.return_ty.clone());
                param_types.insert(symbol.clone(), ext.params.clone());
                sources.insert(symbol.clone(), ext.source);
            }
        }
        ForeignFuncs {
            return_types,
            param_types,
            sources,
        }
    }

    fn get_param_types(&self, symbol: &str) -> Option<&[MirType]> {
        self.param_types.get(symbol).map(|v| v.as_slice())
    }

    fn is_string_return(&self, symbol: &str) -> bool {
        self.return_types
            .get(symbol)
            .map(|ty| matches!(ty, MirType::String))
            .unwrap_or(false)
    }

    fn is_go(&self, symbol: &str) -> bool {
        self.sources
            .get(symbol)
            .map(|s| *s == ForeignSource::Go)
            .unwrap_or(false)
    }

    fn mir_return_ty(&self, symbol: &str) -> Option<&MirType> {
        self.return_types.get(symbol)
    }
}

fn string_type<'ctx>(context: &'ctx Context) -> inkwell::types::StructType<'ctx> {
    context.struct_type(
        &[
            context.ptr_type(inkwell::AddressSpace::default()).into(),
            context.i64_type().into(),
        ],
        false,
    )
}

/// LLVM `br`/conditional branches must use `i1`. Foreign `bool` and some widenings emit `i8`.
fn coerce_condition_to_i1<'ctx>(
    builder: &Builder<'ctx>,
    cond: inkwell::values::IntValue<'ctx>,
) -> Result<inkwell::values::IntValue<'ctx>, String> {
    if cond.get_type().get_bit_width() == 1 {
        return Ok(cond);
    }
    let zero = cond.get_type().const_int(0, false);
    builder
        .build_int_compare(IntPredicate::NE, cond, zero, "cond_i1")
        .map_err(|e| format!("failed to widen branch condition to i1: {e}"))
}

pub fn codegen_module(
    module: &MirModule,
    axon_structs: &HashMap<String, AxonStructInfo>,
    level: OptimizationLevel,
    has_go_deps: bool,
) -> Result<CodegenOutput, String> {
    Target::initialize_native(&InitializationConfig::default())
        .map_err(|e| format!("failed to initialize LLVM native target: {e}"))?;

    let context = Context::create();
    let llvm_module = context.create_module(&module.name);
    let builder = context.create_builder();
    let target_machine = create_target_machine(&llvm_module, level)?;

    let struct_types: HashMap<String, inkwell::types::StructType<'_>> = HashMap::new();

    declare_libc_functions(&context, &llvm_module);

    let mut functions: HashMap<MirCallTarget, FunctionValue<'_>> = HashMap::new();
    for func in &module.functions {
        let fn_value = declare_function(
            &context,
            &llvm_module,
            &module.module_path,
            func,
            axon_structs,
            &struct_types,
        )?;
        functions.insert(
            MirCallTarget::ModuleEntry {
                module_path: module.module_path.clone(),
                entry: func.name.clone(),
            },
            fn_value,
        );
    }

    for ext in &module.external_functions {
        let fn_value = declare_external_function(
            &context,
            &llvm_module,
            ext,
            axon_structs,
            &struct_types,
        )?;
        functions.insert(ext.target.clone(), fn_value);
    }

    let foreign_funcs = ForeignFuncs::from_module(&module.external_functions);

    for func in &module.functions {
        compile_function(
            &context,
            &builder,
            &llvm_module,
            &functions,
            &module.module_path,
            func,
            &foreign_funcs,
            axon_structs,
            &struct_types,
            has_go_deps,
        )?;
    }

    if level == OptimizationLevel::Aggressive {
        build_llvm_pass_pipeline(&llvm_module)?;
    }

    llvm_module
        .verify()
        .map_err(|e| format!("LLVM module verification failed: {e}"))?;

    let ir = llvm_module.print_to_string().to_string();
    let object_data = emit_object_bytes(&llvm_module, &target_machine, &module.name)?;

    Ok(CodegenOutput {
        ir,
        module_name: module.name.clone(),
        object_data,
        c_source: None,
    })
}

fn create_target_machine(
    module: &Module<'_>,
    level: OptimizationLevel,
) -> Result<TargetMachine, String> {
    let triple = TargetMachine::get_default_triple();
    module.set_triple(&triple);

    let target = Target::from_triple(&triple)
        .map_err(|e| format!("failed to resolve LLVM target: {e}"))?;

    let opt_level = match level {
        OptimizationLevel::Debug => inkwell::OptimizationLevel::Default,
        OptimizationLevel::Aggressive => inkwell::OptimizationLevel::Aggressive,
    };

    let target_machine = target
        .create_target_machine(
            &triple,
            "generic",
            "",
            opt_level,
            RelocMode::Default,
            CodeModel::Default,
        )
        .ok_or_else(|| "failed to create LLVM target machine".to_string())?;

    let data_layout = target_machine.get_target_data().get_data_layout();
    module.set_data_layout(&data_layout);
    Ok(target_machine)
}

fn emit_object_bytes(
    module: &Module<'_>,
    target_machine: &TargetMachine,
    _module_name: &str,
) -> Result<Vec<u8>, String> {
    let memory_buffer = target_machine
        .write_to_memory_buffer(module, FileType::Object)
        .map_err(|e| format!("failed to emit object bytes: {e}"))?;
    let bytes = memory_buffer.as_slice().to_vec();
    Ok(bytes)
}

fn build_llvm_pass_pipeline(_module: &Module<'_>) -> Result<(), String> {
    // inkwell 0.8.0 does not expose the legacy PassManagerBuilder API used in
    // the spec (InstructionCombining, Reassociate, GVN, CFGSimplification,
    // PromoteMemoryToRegister). All LLVM optimizations are applied through
    // TargetMachine's OptimizationLevel in create_target_machine(), which
    // handles equivalent optimizations internally. This stub is intentionally
    // empty - no additional passes needed.
    Ok(())
}

fn declare_libc_functions<'ctx>(context: &'ctx Context, module: &Module<'ctx>) {
    let i8_ptr = context.ptr_type(inkwell::AddressSpace::default());

    module.add_function(
        "puts",
        context.i32_type().fn_type(&[i8_ptr.into()], false),
        None,
    );
    module.add_function(
        "printf",
        context.i32_type().fn_type(&[i8_ptr.into()], true),
        None,
    );
    module.add_function("abort", context.void_type().fn_type(&[], false), None);
    module.add_function(
        "axon_builtin_panic",
        context.void_type().fn_type(&[i8_ptr.into(), context.i64_type().into()], false),
        None,
    );
    module.add_function(
        "fflush",
        context.i32_type().fn_type(&[i8_ptr.into()], false),
        None,
    );
    module.add_function(
        "getline",
        context.i64_type().fn_type(
            &[
                i8_ptr.into(),
                context.ptr_type(inkwell::AddressSpace::default()).into(),
                i8_ptr.into(),
            ],
            false,
        ),
        None,
    );
    module.add_function(
        "malloc",
        i8_ptr.fn_type(&[context.i64_type().into()], false),
        None,
    );
    module.add_function(
        "free",
        context.void_type().fn_type(&[i8_ptr.into()], false),
        None,
    );
    module.add_function(
        "strlen",
        context.i64_type().fn_type(&[i8_ptr.into()], false),
        None,
    );
    module.add_function(
        "memcmp",
        context.i32_type().fn_type(
            &[i8_ptr.into(), i8_ptr.into(), context.i64_type().into()],
            false,
        ),
        None,
    );
    module.add_function(
        "memcpy",
        i8_ptr.fn_type(
            &[i8_ptr.into(), i8_ptr.into(), context.i64_type().into()],
            false,
        ),
        None,
    );
    module.add_global(i8_ptr, Some(inkwell::AddressSpace::default()), "stdin");
}

fn mangle_module_entry_symbol(module_path: &str, entry: &str) -> String {
    let sanitized_module = module_path.replace('/', "$");
    format!("axon${}${}", sanitized_module, entry)
}

fn declare_function<'ctx>(
    context: &'ctx Context,
    module: &Module<'ctx>,
    mir_module_path: &str,
    func: &MirFunc,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
) -> Result<FunctionValue<'ctx>, String> {
    let param_types = func
        .params
        .iter()
        .map(|(_, ty, _)| basic_metadata_type(context, ty, axon_structs, struct_types))
        .collect::<Result<Vec<_>, _>>()?;

    let fn_type = if func.name == "main"
        && matches!(
            &func.return_ty,
            MirType::Void | MirType::Unit
        ) {
        context.i32_type().fn_type(&param_types, false)
    } else {
        match &func.return_ty {
            MirType::Void | MirType::Unit => {
                context.void_type().fn_type(&param_types, false)
            }
            ty => basic_type(context, ty, axon_structs, struct_types)?
                .fn_type(&param_types, false),
        }
    };

    let symbol_name = if func.name == "main" {
        "main".to_string()
    } else {
        mangle_module_entry_symbol(mir_module_path, &func.name)
    };

    Ok(module.add_function(&symbol_name, fn_type, None))
}

fn foreign_aware_basic_type<'ctx>(
    context: &'ctx Context,
    ty: &MirType,
    is_foreign: bool,
    is_return: bool,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
) -> Result<BasicTypeEnum<'ctx>, String> {
    if is_foreign {
        match ty {
            MirType::String => {
                if is_return {
                    Ok(context.i32_type().into())
                } else {
                    Ok(context.ptr_type(inkwell::AddressSpace::default()).into())
                }
            }
            MirType::Bool => Ok(context.i8_type().into()),
            _ => basic_type(context, ty, axon_structs, struct_types),
        }
    } else {
        basic_type(context, ty, axon_structs, struct_types)
    }
}

fn declare_external_function<'ctx>(
    context: &'ctx Context,
    module: &Module<'ctx>,
    ext: &MirExternalFunc,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
) -> Result<FunctionValue<'ctx>, String> {
    let is_foreign = matches!(ext.target, MirCallTarget::Foreign { .. });
    let is_go = ext.source == ForeignSource::Go;

    let mut param_types: Vec<BasicMetadataTypeEnum<'ctx>> = Vec::new();
    for ty in &ext.params {
        let basic_ty = foreign_aware_basic_type(
            context,
            ty,
            is_foreign,
            false,
            axon_structs,
            struct_types,
        )?;
        param_types.push(basic_ty.into());
        if is_foreign && matches!(ty, MirType::String) {
            if is_go {
                param_types.push(context.i32_type().into());
            } else {
                param_types.push(context.i64_type().into());
            }
        }
    }

    if is_foreign && matches!(ext.return_ty, MirType::String) {
        let buf_cap_type = if is_go {
            context.i32_type()
        } else {
            context.i64_type()
        };
        param_types.push(context.ptr_type(inkwell::AddressSpace::default()).into());
        param_types.push(buf_cap_type.into());
    }

    let fn_type = match &ext.return_ty {
        MirType::Void | MirType::Unit => {
            context.void_type().fn_type(&param_types, false)
        }
        ty => {
            foreign_aware_basic_type(context, ty, is_foreign, true, axon_structs, struct_types)?
                .fn_type(&param_types, false)
        }
    };

    let symbol_name = match &ext.target {
        MirCallTarget::ModuleEntry { module_path, entry } => {
            mangle_module_entry_symbol(module_path, entry)
        }
        MirCallTarget::Foreign { symbol, .. } => symbol.clone(),
        MirCallTarget::Builtin { .. } => {
            return Err("builtins are not declared as external functions".to_string());
        }
    };

    Ok(module.add_function(&symbol_name, fn_type, None))
}

#[allow(clippy::too_many_arguments)]
fn compile_function<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    functions: &HashMap<MirCallTarget, FunctionValue<'ctx>>,
    mir_module_path: &str,
    func: &MirFunc,
    foreign_funcs: &ForeignFuncs,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
    has_go_deps: bool,
) -> Result<(), String> {
    let function = *functions
        .get(&MirCallTarget::ModuleEntry {
            module_path: mir_module_path.to_string(),
            entry: func.name.clone(),
        })
        .ok_or_else(|| format!("missing function declaration for '{}'", func.name))?;

    let mut blocks = HashMap::new();
    for block in &func.blocks {
        let bb = context.append_basic_block(function, &block.label);
        blocks.insert(block.label.clone(), bb);
    }

    let mut locals = HashMap::new();
    let mut local_struct_names: HashMap<LocalId, String> = HashMap::new();
    let entry = blocks
        .get(&func.entry_block)
        .copied()
        .ok_or_else(|| format!("missing entry block '{}'", func.entry_block))?;
    builder.position_at_end(entry);

    for (index, (_, ty, local_id)) in func.params.iter().enumerate() {
        if let MirType::Struct(name, _) = ty {
            local_struct_names.insert(*local_id, name.clone());
        }
        let ptr = build_alloca(
            builder,
            context,
            function,
            *local_id,
            ty,
            axon_structs,
            struct_types,
        )?;
        let llvm_ty = basic_type(context, ty, axon_structs, struct_types)?;
        let param = function
            .get_nth_param(index as u32)
            .ok_or_else(|| format!("missing parameter {index} for '{}'", func.name))?;
        builder
            .build_store(ptr, param)
            .map_err(|e| format!("failed to store parameter: {e}"))?;
        locals.insert(*local_id, (ptr, llvm_ty));
    }

    for local in &func.locals {
        if let MirType::Struct(name, _) = &local.ty {
            local_struct_names.insert(local.id, name.clone());
        }
        if let std::collections::hash_map::Entry::Vacant(entry) = locals.entry(local.id) {
            if matches!(local.ty, MirType::Void | MirType::Unit) {
                continue;
            }
            let ptr = build_alloca(
                builder,
                context,
                function,
                local.id,
                &local.ty,
                axon_structs,
                struct_types,
            )?;
            let llvm_ty = basic_type(context, &local.ty, axon_structs, struct_types)?;
            entry.insert((ptr, llvm_ty));
        }
    }

    if func.name == "main" && has_go_deps {
        let wait_fn = module.add_function(
            "_cgo_wait_runtime_init_done",
            context.void_type().fn_type(&[], false),
            None,
        );
        builder
            .build_call(wait_fn, &[], "go_runtime_wait")
            .map_err(|e| format!("failed to build go runtime wait call: {e}"))?;
    }

    for block in &func.blocks {
        let llvm_block = blocks[&block.label];
        builder.position_at_end(llvm_block);

        for stmt in &block.stmts {
            compile_stmt(
                context,
                builder,
                module,
                functions,
                function,
                &mut locals,
                &local_struct_names,
                stmt,
                foreign_funcs,
                &blocks,
                axon_structs,
                struct_types,
                &func.owned_locals,
                &func.string_literal_locals,
                &func.struct_literal_fields,
            )?;
        }

        let current = builder.get_insert_block().unwrap_or(llvm_block);
        if current.get_terminator().is_none() {
            compile_terminator(
                context,
                builder,
                module,
                functions,
                &blocks,
                &locals,
                &local_struct_names,
                &func.return_ty,
                &func.name,
                &block.terminator,
                foreign_funcs,
                axon_structs,
                struct_types,
                &func.owned_locals,
                &func.string_literal_locals,
            )?;
        }
    }

    Ok(())
}

fn build_alloca<'ctx>(
    _builder: &Builder<'ctx>,
    context: &'ctx Context,
    function: FunctionValue<'ctx>,
    local_id: LocalId,
    ty: &MirType,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
) -> Result<PointerValue<'ctx>, String> {
    let entry = function
        .get_first_basic_block()
        .ok_or_else(|| "function has no entry block".to_string())?;
    let temp_builder = context.create_builder();
    if let Some(instr) = entry.get_first_instruction() {
        temp_builder.position_before(&instr);
    } else {
        temp_builder.position_at_end(entry);
    }

    temp_builder
        .build_alloca(
            basic_type(context, ty, axon_structs, struct_types)?,
            &format!("local_{}", local_id.0),
        )
        .map_err(|e| format!("failed to allocate local: {e}"))
}

fn build_alloca_for_basic_type<'ctx>(
    _builder: &Builder<'ctx>,
    context: &'ctx Context,
    function: FunctionValue<'ctx>,
    local_id: LocalId,
    ty: BasicTypeEnum<'ctx>,
) -> Result<PointerValue<'ctx>, String> {
    let entry = function
        .get_first_basic_block()
        .ok_or_else(|| "function has no entry block".to_string())?;
    let temp_builder = context.create_builder();
    if let Some(instr) = entry.get_first_instruction() {
        temp_builder.position_before(&instr);
    } else {
        temp_builder.position_at_end(entry);
    }

    temp_builder
        .build_alloca(ty, &format!("local_{}", local_id.0))
        .map_err(|e| format!("failed to allocate local: {e}"))
}

#[allow(clippy::too_many_arguments)]
fn compile_stmt<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    functions: &HashMap<MirCallTarget, FunctionValue<'ctx>>,
    function: FunctionValue<'ctx>,
    locals: &mut HashMap<LocalId, (PointerValue<'ctx>, BasicTypeEnum<'ctx>)>,
    local_struct_names: &HashMap<LocalId, String>,
    stmt: &MirStmt,
    foreign_funcs: &ForeignFuncs,
    blocks: &HashMap<String, inkwell::basic_block::BasicBlock<'ctx>>,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
    owned_locals: &HashSet<u32>,
    string_literal_locals: &HashSet<u32>,
    struct_literal_fields: &HashMap<u32, HashSet<String>>,
) -> Result<(), String> {
    match stmt {
        MirStmt::Assign { target, value } => {
            let value = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                value,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            let value_ty = value.get_type();
            let (ptr, _) = if let Some(local) = locals.get(target).copied() {
                local
            } else {
                let ptr =
                    build_alloca_for_basic_type(builder, context, function, *target, value_ty)?;
                locals.insert(*target, (ptr, value_ty));
                (ptr, value_ty)
            };
            builder
                .build_store(ptr, value)
                .map_err(|e| format!("failed to store local {}: {e}", target.0))?;
            Ok(())
        }
        MirStmt::Call {
            target,
            callee,
            args,
        } => {
            let call_result = compile_call_target(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                callee,
                args,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            if let Some(target) = target
                && let Some(value) = call_result
            {
                let value_ty = value.get_type();
                let (ptr, _) = if let Some(local) = locals.get(target).copied() {
                    local
                } else {
                    let ptr = build_alloca_for_basic_type(
                        builder, context, function, *target, value_ty,
                    )?;
                    locals.insert(*target, (ptr, value_ty));
                    (ptr, value_ty)
                };
                builder
                    .build_store(ptr, value)
                    .map_err(|e| format!("failed to store call result: {e}"))?;
            }
            Ok(())
        }
        MirStmt::ConstructOptionSome { target, value, ty } => {
            let option_ty = basic_type(context, ty, axon_structs, struct_types)?;
            let option_ptr = if let Some((ptr, _)) = locals.get(target).copied() {
                ptr
            } else {
                let ptr = build_alloca_for_basic_type(
                    builder, context, function, *target, option_ty,
                )?;
                locals.insert(*target, (ptr, option_ty));
                ptr
            };
            let tag_ptr = builder
                .build_struct_gep(option_ty, option_ptr, 0, "option_tag_ptr")
                .map_err(|e| format!("failed to get tag pointer: {e}"))?;
            builder
                .build_store(tag_ptr, context.bool_type().const_int(1, false))
                .map_err(|e| format!("failed to store option tag: {e}"))?;
            let payload_ptr = builder
                .build_struct_gep(option_ty, option_ptr, 1, "option_payload_ptr")
                .map_err(|e| format!("failed to get payload pointer: {e}"))?;
            let value_val = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                value,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            let value_ptr = builder
                .build_pointer_cast(
                    payload_ptr,
                    context.ptr_type(inkwell::AddressSpace::default()),
                    "payload_cast",
                )
                .map_err(|e| format!("failed to cast payload pointer: {e}"))?;
            builder
                .build_store(value_ptr, value_val)
                .map_err(|e| format!("failed to store option payload: {e}"))?;
            Ok(())
        }
        MirStmt::ConstructOptionNone { target, ty } => {
            let option_ty = basic_type(context, ty, axon_structs, struct_types)?;
            let option_ptr = if let Some((ptr, _)) = locals.get(target).copied() {
                ptr
            } else {
                let ptr = build_alloca_for_basic_type(
                    builder, context, function, *target, option_ty,
                )?;
                locals.insert(*target, (ptr, option_ty));
                ptr
            };
            let tag_ptr = builder
                .build_struct_gep(option_ty, option_ptr, 0, "option_tag_ptr")
                .map_err(|e| format!("failed to get tag pointer: {e}"))?;
            builder
                .build_store(tag_ptr, context.bool_type().const_int(0, false))
                .map_err(|e| format!("failed to store option none tag: {e}"))?;
            Ok(())
        }
        MirStmt::ConstructResultOk { target, value, ty } => {
            let result_ty = basic_type(context, ty, axon_structs, struct_types)?;
            let result_ptr = if let Some((ptr, _)) = locals.get(target).copied() {
                ptr
            } else {
                let ptr = build_alloca_for_basic_type(
                    builder, context, function, *target, result_ty,
                )?;
                locals.insert(*target, (ptr, result_ty));
                ptr
            };
            let tag_ptr = builder
                .build_struct_gep(result_ty, result_ptr, 0, "result_tag_ptr")
                .map_err(|e| format!("failed to get result tag pointer: {e}"))?;
            builder
                .build_store(tag_ptr, context.i32_type().const_int(0, false))
                .map_err(|e| format!("failed to store result ok tag: {e}"))?;
            let payload_ptr = builder
                .build_struct_gep(result_ty, result_ptr, 1, "result_payload_ptr")
                .map_err(|e| format!("failed to get result payload pointer: {e}"))?;
            let value_val = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                value,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            let value_ptr = builder
                .build_pointer_cast(
                    payload_ptr,
                    context.ptr_type(inkwell::AddressSpace::default()),
                    "result_payload_cast",
                )
                .map_err(|e| format!("failed to cast result payload pointer: {e}"))?;
            builder
                .build_store(value_ptr, value_val)
                .map_err(|e| format!("failed to store result ok payload: {e}"))?;
            Ok(())
        }
        MirStmt::ConstructResultErr { target, value, ty } => {
            let result_ty = basic_type(context, ty, axon_structs, struct_types)?;
            let result_ptr = if let Some((ptr, _)) = locals.get(target).copied() {
                ptr
            } else {
                let ptr = build_alloca_for_basic_type(
                    builder, context, function, *target, result_ty,
                )?;
                locals.insert(*target, (ptr, result_ty));
                ptr
            };
            let tag_ptr = builder
                .build_struct_gep(result_ty, result_ptr, 0, "result_tag_ptr")
                .map_err(|e| format!("failed to get result tag pointer: {e}"))?;
            builder
                .build_store(tag_ptr, context.i32_type().const_int(1, false))
                .map_err(|e| format!("failed to store result err tag: {e}"))?;
            let payload_ptr = builder
                .build_struct_gep(result_ty, result_ptr, 1, "result_payload_ptr")
                .map_err(|e| format!("failed to get result payload pointer: {e}"))?;
            let value_val = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                value,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            let value_ptr = builder
                .build_pointer_cast(
                    payload_ptr,
                    context.ptr_type(inkwell::AddressSpace::default()),
                    "result_err_payload_cast",
                )
                .map_err(|e| format!("failed to cast result err payload pointer: {e}"))?;
            builder
                .build_store(value_ptr, value_val)
                .map_err(|e| format!("failed to store result err payload: {e}"))?;
            Ok(())
        }
        MirStmt::InspectOption {
            value,
            some_target,
            none_target,
        } => {
            let (val_ptr, val_ty) = locals
                .get(value)
                .copied()
                .ok_or_else(|| format!("missing local for InspectOption value {}", value.0))?;
            let tag_ptr = builder
                .build_struct_gep(val_ty, val_ptr, 0, "inspect_option_tag_ptr")
                .map_err(|e| format!("failed to get option tag pointer: {e}"))?;
            let tag = builder
                .build_load(context.bool_type(), tag_ptr, "inspect_option_tag")
                .map_err(|e| format!("failed to load option tag: {e}"))?;
            let some_bb = blocks
                .get(&some_target.0)
                .copied()
                .ok_or_else(|| format!("missing some block '{}'", some_target.0))?;
            let none_bb = blocks
                .get(&none_target.0)
                .copied()
                .ok_or_else(|| format!("missing none block '{}'", none_target.0))?;
            builder
                .build_conditional_branch(tag.into_int_value(), some_bb, none_bb)
                .map_err(|e| format!("failed to build option inspect branch: {e}"))?;
            Ok(())
        }
        MirStmt::InspectResult {
            value,
            ok_target,
            err_target,
        } => {
            let (val_ptr, val_ty) = locals
                .get(value)
                .copied()
                .ok_or_else(|| format!("missing local for InspectResult value {}", value.0))?;
            let tag_ptr = builder
                .build_struct_gep(val_ty, val_ptr, 0, "inspect_result_tag_ptr")
                .map_err(|e| format!("failed to get result tag pointer: {e}"))?;
            let tag = builder
                .build_load(context.i32_type(), tag_ptr, "inspect_result_tag")
                .map_err(|e| format!("failed to load result tag: {e}"))?;
            let zero = context.i32_type().const_int(0, false);
            let is_ok = builder
                .build_int_compare(IntPredicate::EQ, tag.into_int_value(), zero, "is_ok")
                .map_err(|e| format!("failed to compare result tag: {e}"))?;
            let ok_bb = blocks
                .get(&ok_target.0)
                .copied()
                .ok_or_else(|| format!("missing ok block '{}'", ok_target.0))?;
            let err_bb = blocks
                .get(&err_target.0)
                .copied()
                .ok_or_else(|| format!("missing err block '{}'", err_target.0))?;
            builder
                .build_conditional_branch(is_ok, ok_bb, err_bb)
                .map_err(|e| format!("failed to build result inspect branch: {e}"))?;
            Ok(())
        }
        MirStmt::ExtractResultOk { source, target } => {
            let (source_ptr, source_ty) = locals.get(source).copied().ok_or_else(|| {
                format!("missing local for ExtractResultOk source {}", source.0)
            })?;
            let (target_ptr, target_llvm_ty) =
                locals.get(target).copied().ok_or_else(|| {
                    format!("missing local for ExtractResultOk target {}", target.0)
                })?;
            let payload_ptr = builder
                .build_struct_gep(source_ty, source_ptr, 1, "extract_result_ok_payload")
                .map_err(|e| {
                    format!("failed to get result payload pointer for extraction: {e}")
                })?;
            let generic_ptr = builder
                .build_pointer_cast(
                    payload_ptr,
                    context.ptr_type(inkwell::AddressSpace::default()),
                    "extract_result_ok_cast",
                )
                .map_err(|e| {
                    format!("failed to cast result payload pointer for extraction: {e}")
                })?;
            let loaded = builder
                .build_load(target_llvm_ty, generic_ptr, "extracted_result_ok")
                .map_err(|e| format!("failed to load extracted result ok value: {e}"))?;
            builder
                .build_store(target_ptr, loaded)
                .map_err(|e| format!("failed to store extracted result ok value: {e}"))?;
            Ok(())
        }
        MirStmt::ExtractResultErr { source, target } => {
            let (source_ptr, source_ty) = locals.get(source).copied().ok_or_else(|| {
                format!("missing local for ExtractResultErr source {}", source.0)
            })?;
            let (target_ptr, target_llvm_ty) =
                locals.get(target).copied().ok_or_else(|| {
                    format!("missing local for ExtractResultErr target {}", target.0)
                })?;
            let payload_ptr = builder
                .build_struct_gep(source_ty, source_ptr, 1, "extract_result_err_payload")
                .map_err(|e| {
                    format!("failed to get result err payload pointer for extraction: {e}")
                })?;
            let generic_ptr = builder
                .build_pointer_cast(
                    payload_ptr,
                    context.ptr_type(inkwell::AddressSpace::default()),
                    "extract_result_err_cast",
                )
                .map_err(|e| {
                    format!("failed to cast result err payload pointer for extraction: {e}")
                })?;
            let loaded = builder
                .build_load(target_llvm_ty, generic_ptr, "extracted_result_err")
                .map_err(|e| format!("failed to load extracted result err value: {e}"))?;
            builder
                .build_store(target_ptr, loaded)
                .map_err(|e| format!("failed to store extracted result err value: {e}"))?;
            Ok(())
        }
        MirStmt::ExtractOptionSome { source, target } => {
            let (source_ptr, source_ty) = locals.get(source).copied().ok_or_else(|| {
                format!("missing local for ExtractOptionSome source {}", source.0)
            })?;
            let (target_ptr, target_llvm_ty) =
                locals.get(target).copied().ok_or_else(|| {
                    format!("missing local for ExtractOptionSome target {}", target.0)
                })?;
            let payload_ptr = builder
                .build_struct_gep(source_ty, source_ptr, 1, "extract_option_some_payload")
                .map_err(|e| {
                    format!("failed to get option payload pointer for extraction: {e}")
                })?;
            let generic_ptr = builder
                .build_pointer_cast(
                    payload_ptr,
                    context.ptr_type(inkwell::AddressSpace::default()),
                    "extract_option_some_cast",
                )
                .map_err(|e| {
                    format!("failed to cast option payload pointer for extraction: {e}")
                })?;
            let loaded = builder
                .build_load(target_llvm_ty, generic_ptr, "extracted_option_some")
                .map_err(|e| format!("failed to load extracted option some value: {e}"))?;
            builder
                .build_store(target_ptr, loaded)
                .map_err(|e| format!("failed to store extracted option some value: {e}"))?;
            Ok(())
        }
        MirStmt::ConstructStruct {
            target,
            name,
            fields,
        } => {
            let struct_ty = basic_type(
                context,
                &MirType::Struct(name.clone(), vec![]),
                axon_structs,
                struct_types,
            )?;
            let struct_ptr = if let Some((ptr, _)) = locals.get(target).copied() {
                ptr
            } else {
                let ptr = build_alloca_for_basic_type(
                    builder, context, function, *target, struct_ty,
                )?;
                locals.insert(*target, (ptr, struct_ty));
                ptr
            };
            for (field_name, field_expr) in fields {
                let field_index = axon_structs
                    .get(name)
                    .and_then(|s| s.fields.iter().position(|(f, _)| f == field_name))
                    .ok_or_else(|| {
                        format!("field '{}' not found in struct '{}'", field_name, name)
                    })?;
                let field_ptr = builder
                    .build_struct_gep(
                        struct_ty,
                        struct_ptr,
                        field_index as u32,
                        "construct_field_ptr",
                    )
                    .map_err(|e| {
                        format!("failed to get field pointer for construction: {e}")
                    })?;
                let field_value = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    field_expr,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                builder
                    .build_store(field_ptr, field_value)
                    .map_err(|e| format!("failed to store field value in construction: {e}"))?;
            }
            Ok(())
        }
        MirStmt::StoreStructField {
            target,
            field,
            value,
        } => {
            let (target_ptr, struct_ty) = locals.get(target).copied().ok_or_else(|| {
                format!("missing local for StoreStructField target {}", target.0)
            })?;
            let struct_ty = match struct_ty {
                BasicTypeEnum::StructType(st) => st,
                _ => return Err("StoreStructField requires a struct type".to_string()),
            };
            let struct_name = local_struct_names
                .get(target)
                .ok_or_else(|| format!("local {} is not a struct type", target.0))?;
            let field_index = axon_structs
                .get(struct_name)
                .and_then(|s| s.fields.iter().position(|(f, _)| f == field))
                .ok_or_else(|| {
                    format!("field '{}' not found in struct '{}'", field, struct_name)
                })?;
            let field_ptr = builder
                .build_struct_gep(struct_ty, target_ptr, field_index as u32, "store_field_ptr")
                .map_err(|e| format!("failed to get field pointer for store: {e}"))?;
            let value_val = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                value,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            builder
                .build_store(field_ptr, value_val)
                .map_err(|e| format!("failed to store struct field: {e}"))?;
            Ok(())
        }
        MirStmt::CleanupAggregateShell {
            local,
            struct_name,
            field_modes,
        } => {
            // Only clean up if the local is still a canonical owner.
            // If moved/returned/pointer-backed, skip cleanup entirely.
            if !owned_locals.contains(&local.0) {
                return Ok(());
            }
            let (local_ptr, local_ty) = locals.get(local).copied().ok_or_else(|| {
                format!("missing local for CleanupAggregateShell {}", local.0)
            })?;
            let struct_ty = match local_ty {
                BasicTypeEnum::StructType(st) => st,
                _ => {
                    return Err(format!(
                        "CleanupAggregateShell requires a struct type, got {:?}",
                        local_ty
                    ));
                }
            };
            compile_aggregate_shell_cleanup(
                context,
                builder,
                module,
                local_ptr,
                struct_ty,
                struct_name,
                axon_structs,
                struct_types,
                owned_locals,
                field_modes,
                struct_literal_fields,
                *local,
            )?;
            Ok(())
        }
        MirStmt::DestructureTuple { source, targets } => {
            // Tuple destructuring: extract each element from the source tuple
            // and store into target locals.
            let (src_ptr, src_ty) = locals.get(source).copied().ok_or_else(|| {
                format!("missing local for DestructureTuple source {}", source.0)
            })?;
            let struct_ty = match src_ty {
                BasicTypeEnum::StructType(st) => st,
                _ => {
                    return Err(format!(
                        "DestructureTuple requires a struct (tuple) type, got {:?}",
                        src_ty
                    ));
                }
            };
            for (i, target) in targets.iter().enumerate() {
                let (target_ptr, _target_ty) =
                    locals.get(target).copied().ok_or_else(|| {
                        format!("missing target local {} for DestructureTuple", target.0)
                    })?;
                let elem_ptr = builder
                    .build_struct_gep(
                        struct_ty,
                        src_ptr,
                        i as u32,
                        &format!("tuple_elem_{}", i),
                    )
                    .map_err(|e| format!("failed to get tuple element pointer: {e}"))?;
                let elem_val = builder
                    .build_load(
                        struct_ty.get_field_type_at_index(i as u32).unwrap(),
                        elem_ptr,
                        &format!("tuple_val_{}", i),
                    )
                    .map_err(|e| format!("failed to load tuple element: {e}"))?;
                builder
                    .build_store(target_ptr, elem_val)
                    .map_err(|e| format!("failed to store tuple element: {e}"))?;
            }
            Ok(())
        }
        _ => Err("stmt variant not yet supported in this codegen path".to_string()),
    }
}

#[allow(clippy::too_many_arguments)]
fn compile_terminator<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    functions: &HashMap<MirCallTarget, FunctionValue<'ctx>>,
    blocks: &HashMap<String, inkwell::basic_block::BasicBlock<'ctx>>,
    locals: &HashMap<LocalId, (PointerValue<'ctx>, BasicTypeEnum<'ctx>)>,
    local_struct_names: &HashMap<LocalId, String>,
    return_ty: &MirType,
    func_name: &str,
    terminator: &MirTerminator,
    foreign_funcs: &ForeignFuncs,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
    owned_locals: &HashSet<u32>,
    string_literal_locals: &HashSet<u32>,
) -> Result<(), String> {
    match terminator {
        MirTerminator::Return(value) => {
            match value {
                Some(expr) => {
                    let value = compile_expr(
                        context,
                        builder,
                        module,
                        functions,
                        locals,
                        local_struct_names,
                        expr,
                        foreign_funcs,
                        axon_structs,
                        struct_types,
                        owned_locals,
                        string_literal_locals,
                    )?;
                    let value = coerce_to_type(
                        context,
                        builder,
                        value,
                        return_ty,
                        axon_structs,
                        struct_types,
                    )?;
                    builder
                        .build_return(Some(&value))
                        .map_err(|e| format!("failed to build return: {e}"))?;
                }
                None => {
                    if func_name == "main"
                        && matches!(
                            return_ty,
                            MirType::Void | MirType::Unit
                        )
                    {
                        let zero = context.i32_type().const_int(0, false);
                        builder
                            .build_return(Some(&zero))
                            .map_err(|e| format!("failed to build main return: {e}"))?;
                    } else if matches!(
                        return_ty,
                        MirType::Void | MirType::Unit
                    ) {
                        builder
                            .build_return(None)
                            .map_err(|e| format!("failed to build void return: {e}"))?;
                    } else {
                        return Err("missing return value for non-void function".to_string());
                    }
                }
            }
            Ok(())
        }
        MirTerminator::Goto(label) => {
            let block = blocks
                .get(label)
                .copied()
                .ok_or_else(|| format!("unknown block '{label}'"))?;
            builder
                .build_unconditional_branch(block)
                .map_err(|e| format!("failed to build branch: {e}"))?;
            Ok(())
        }
        MirTerminator::Branch {
            cond,
            then_block,
            else_block,
        } => {
            let cond_val = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                cond,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            if !cond_val.is_int_value() {
                return Err("branch condition must be an integer value".to_string());
            }
            let cond = coerce_condition_to_i1(builder, cond_val.into_int_value())?;
            let then_block = blocks
                .get(then_block)
                .copied()
                .ok_or_else(|| format!("unknown block '{then_block}'"))?;
            let else_block = blocks
                .get(else_block)
                .copied()
                .ok_or_else(|| format!("unknown block '{else_block}'"))?;
            builder
                .build_conditional_branch(cond, then_block, else_block)
                .map_err(|e| format!("failed to build conditional branch: {e}"))?;
            Ok(())
        }
        MirTerminator::Unreachable => {
            builder
                .build_unreachable()
                .map_err(|e| format!("failed to build unreachable: {e}"))?;
            Ok(())
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn compile_expr<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    functions: &HashMap<MirCallTarget, FunctionValue<'ctx>>,
    locals: &HashMap<LocalId, (PointerValue<'ctx>, BasicTypeEnum<'ctx>)>,
    local_struct_names: &HashMap<LocalId, String>,
    expr: &MirExpr,
    foreign_funcs: &ForeignFuncs,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
    owned_locals: &HashSet<u32>,
    string_literal_locals: &HashSet<u32>,
) -> Result<BasicValueEnum<'ctx>, String> {
    match expr {
        MirExpr::Local(id) => {
            let (ptr, ty) = locals
                .get(id)
                .copied()
                .ok_or_else(|| format!("missing local {}", id.0))?;
            builder
                .build_load(ty, ptr, &format!("load_{}", id.0))
                .map_err(|e| format!("failed to load local {}: {e}", id.0))
        }
        MirExpr::Const(value) => compile_const(context, builder, value),
        MirExpr::BinOp { op, left, right } => {
            let left_val = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                left,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            let right_val = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                right,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            let is_left_owned = is_expr_owned(left, owned_locals, string_literal_locals);
            let is_right_owned = is_expr_owned(right, owned_locals, string_literal_locals);
            compile_binop(
                context,
                builder,
                module,
                op,
                left_val,
                right_val,
                is_left_owned,
                is_right_owned,
            )
        }
        MirExpr::UnOp { op, operand } => {
            let value = compile_expr(
                context,
                builder,
                module,
                functions,
                locals,
                local_struct_names,
                operand,
                foreign_funcs,
                axon_structs,
                struct_types,
                owned_locals,
                string_literal_locals,
            )?;
            match op {
                MirUnOp::Neg => {
                    if value.is_float_value() {
                        builder
                            .build_float_neg(value.into_float_value(), "fneg")
                            .map(BasicValueEnum::from)
                            .map_err(|e| format!("failed to build float negation: {e}"))
                    } else {
                        builder
                            .build_int_neg(value.into_int_value(), "ineg")
                            .map(BasicValueEnum::from)
                            .map_err(|e| format!("failed to build int negation: {e}"))
                    }
                }
                MirUnOp::Not => builder
                    .build_not(value.into_int_value(), "not")
                    .map(BasicValueEnum::from)
                    .map_err(|e| format!("failed to build not: {e}")),
            }
        }
        MirExpr::Call { target, args, .. } => compile_call_target(
            context,
            builder,
            module,
            functions,
            locals,
            local_struct_names,
            target,
            args,
            foreign_funcs,
            axon_structs,
            struct_types,
            owned_locals,
            string_literal_locals,
        )?
        .ok_or_else(|| format!("call to '{:?}' does not produce a value", target)),
        MirExpr::LoadStructField { source, field, ty } => {
            let (ptr, struct_ty) = locals.get(source).copied().ok_or_else(|| {
                format!("missing local for LoadStructField source {}", source.0)
            })?;
            let struct_ty = match struct_ty {
                BasicTypeEnum::StructType(st) => st,
                _ => return Err("LoadStructField requires a struct type".to_string()),
            };
            let struct_name = local_struct_names
                .get(source)
                .ok_or_else(|| format!("local {} is not a struct type", source.0))?;
            let field_index = axon_structs
                .get(struct_name)
                .and_then(|s| s.fields.iter().position(|(f, _)| f == field))
                .ok_or_else(|| {
                    format!("field '{}' not found in struct '{}'", field, struct_name)
                })?;
            let field_ptr = builder
                .build_struct_gep(struct_ty, ptr, field_index as u32, "struct_field_ptr")
                .map_err(|e| format!("failed to get struct field pointer: {e}"))?;
            let field_ty = basic_type(context, ty, axon_structs, struct_types)?;
            builder
                .build_load(field_ty, field_ptr, "struct_field_value")
                .map_err(|e| format!("failed to load struct field: {e}"))
        }
        MirExpr::Tuple(ids) => {
            // Tuple value: construct a struct from individual local values.
            // Tuples are path groups only, no shell cleanup.
            let mut elem_types = Vec::with_capacity(ids.len());
            let mut elem_values = Vec::with_capacity(ids.len());
            for id in ids {
                let (ptr, ty) = locals
                    .get(id)
                    .copied()
                    .ok_or_else(|| format!("missing local for Tuple element {}", id.0))?;
                let val = builder
                    .build_load(ty, ptr, &format!("tuple_elem_{}", id.0))
                    .map_err(|e| format!("failed to load tuple element: {e}"))?;
                elem_values.push(val);
                elem_types.push(ty);
            }
            let struct_ty = context.struct_type(&elem_types, false);
            // Use insert_value chain (not const_named_struct) because the
            // element values are runtime instructions, not constants.
            let mut accum = struct_ty.get_undef().as_aggregate_value_enum();
            for (i, val) in elem_values.into_iter().enumerate() {
                accum = builder
                    .build_insert_value(accum, val, i as u32, &format!("tuple_ins_{}", i))
                    .map_err(|e| format!("failed to insert tuple element: {e}"))?;
            }
            Ok(accum.as_basic_value_enum())
        }
        MirExpr::LoadListLen { .. } | MirExpr::LoadListIndex { .. } => Err(
            "list load expressions are not yet supported in this codegen path".to_string(),
        ),
    }
}

fn compile_const<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    value: &MirValue,
) -> Result<BasicValueEnum<'ctx>, String> {
    match value {
        MirValue::Int { value, width } => {
            let sign_extend = matches!(
                width,
                IntWidth::I8 | IntWidth::I16 | IntWidth::I32 | IntWidth::I64
            );
            let int_val = match width {
                IntWidth::I8 | IntWidth::U8 => {
                    context.i8_type().const_int(*value as u64, sign_extend)
                }
                IntWidth::I16 | IntWidth::U16 => {
                    context.i16_type().const_int(*value as u64, sign_extend)
                }
                IntWidth::I32 | IntWidth::U32 => {
                    context.i32_type().const_int(*value as u64, sign_extend)
                }
                IntWidth::I64 | IntWidth::U64 => {
                    context.i64_type().const_int(*value as u64, sign_extend)
                }
            };
            Ok(int_val.into())
        }
        MirValue::Float(n) => Ok(context.f64_type().const_float(*n).into()),
        MirValue::Bool(b) => Ok(context.bool_type().const_int(u64::from(*b), false).into()),
        MirValue::String(s) => {
            let ptr = builder
                .build_global_string_ptr(s, "str")
                .map_err(|e| format!("failed to build string constant: {e}"))?;
            let len = context.i64_type().const_int(s.len() as u64, false);
            let st = string_type(context);
            let value = st.const_named_struct(&[ptr.as_pointer_value().into(), len.into()]);
            Ok(value.into())
        }
        MirValue::Unit => {
            Err("unit value is not representable in LLVM expressions".to_string())
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn compile_binop<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    op: &MirBinOp,
    left: BasicValueEnum<'ctx>,
    right: BasicValueEnum<'ctx>,
    is_left_owned: bool,
    is_right_owned: bool,
) -> Result<BasicValueEnum<'ctx>, String> {
    // Handle string equality/inequality
    if (matches!(op, MirBinOp::Eq | MirBinOp::Ne))
        && left.is_struct_value()
        && right.is_struct_value()
    {
        let left_struct = left.into_struct_value();
        let right_struct = right.into_struct_value();

        // Extract ptr and len from both strings
        let left_ptr = builder
            .build_extract_value(left_struct, 0, "left.ptr")
            .map_err(|e| format!("failed to extract left string ptr: {e}"))?;
        let left_len = builder
            .build_extract_value(left_struct, 1, "left.len")
            .map_err(|e| format!("failed to extract left string len: {e}"))?;
        let right_ptr = builder
            .build_extract_value(right_struct, 0, "right.ptr")
            .map_err(|e| format!("failed to extract right string ptr: {e}"))?;
        let right_len = builder
            .build_extract_value(right_struct, 1, "right.len")
            .map_err(|e| format!("failed to extract right string len: {e}"))?;

        let left_ptr = left_ptr.into_pointer_value();
        let left_len = left_len.into_int_value();
        let right_ptr = right_ptr.into_pointer_value();
        let right_len = right_len.into_int_value();

        // Fast path: compare lengths first
        let len_eq = builder
            .build_int_compare(IntPredicate::EQ, left_len, right_len, "len.eq")
            .map_err(|e| format!("failed to compare lengths: {e}"))?;

        // Create blocks for conditional logic
        let function = builder
            .get_insert_block()
            .and_then(|b| b.get_parent())
            .unwrap();
        let entry_block = builder.get_insert_block().unwrap();
        let content_cmp_block = context.append_basic_block(function, "content_cmp");
        let done_block = context.append_basic_block(function, "done");

        // If lengths differ, we know the result
        builder
            .build_conditional_branch(len_eq, content_cmp_block, done_block)
            .map_err(|e| format!("failed to build conditional branch: {e}"))?;

        // content_cmp: lengths equal, compare content with memcmp
        builder.position_at_end(content_cmp_block);
        let memcmp_fn = module
            .get_function("memcmp")
            .ok_or_else(|| "missing memcmp declaration".to_string())?;

        let i32_type = context.i32_type();
        let memcmp_result = builder
            .build_call(
                memcmp_fn,
                &[left_ptr.into(), right_ptr.into(), left_len.into()],
                "memcmp.result",
            )
            .map_err(|e| format!("failed to build memcmp call: {e}"))?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| "memcmp should return a value".to_string())?
            .into_int_value();

        let content_eq = builder
            .build_int_compare(
                IntPredicate::EQ,
                memcmp_result,
                i32_type.const_int(0, false),
                "content.eq",
            )
            .map_err(|e| format!("failed to compare memcmp result: {e}"))?;

        builder
            .build_unconditional_branch(done_block)
            .map_err(|e| format!("failed to build unconditional branch: {e}"))?;

        // done: phi between the two results
        builder.position_at_end(done_block);
        let phi = builder
            .build_phi(context.bool_type(), "result")
            .map_err(|e| format!("failed to build phi: {e}"))?;

        let false_val = context.bool_type().const_int(0, false);
        phi.add_incoming(&[(&false_val, entry_block)]);
        phi.add_incoming(&[(&content_eq, content_cmp_block)]);

        let result = phi.as_basic_value();

        // Do not consume/free comparison operands here.
        // In chained conditions (if/elif), the same string local may be compared
        // multiple times; eager free in the first compare causes use-after-free
        // and double-free. Ownership cleanup should happen at the canonical end
        // of the owner's lifetime, not at each comparison.

        // Invert for inequality
        if matches!(op, MirBinOp::Ne) {
            return builder
                .build_not(result.into_int_value(), "ineq")
                .map(Into::into)
                .map_err(|e| format!("failed to build not: {e}"));
        }
        return Ok(result);
    }

    // Handle string concatenation (Add with two struct values = strings)
    if matches!(op, MirBinOp::Add) && left.is_struct_value() && right.is_struct_value() {
        let left_struct = left.into_struct_value();
        let right_struct = right.into_struct_value();
        let left_ptr = builder
            .build_extract_value(left_struct, 0, "l.ptr")
            .map_err(|e| format!("extract left ptr: {e}"))?
            .into_pointer_value();
        let left_len = builder
            .build_extract_value(left_struct, 1, "l.len")
            .map_err(|e| format!("extract left len: {e}"))?
            .into_int_value();
        let right_ptr = builder
            .build_extract_value(right_struct, 0, "r.ptr")
            .map_err(|e| format!("extract right ptr: {e}"))?
            .into_pointer_value();
        let right_len = builder
            .build_extract_value(right_struct, 1, "r.len")
            .map_err(|e| format!("extract right len: {e}"))?
            .into_int_value();

        let total_len = builder
            .build_int_add(left_len, right_len, "total.len")
            .map_err(|e| format!("add lens: {e}"))?;
        let malloc_fn = module
            .get_function("malloc")
            .ok_or_else(|| "missing malloc declaration".to_string())?;
        let buf = builder
            .build_call(malloc_fn, &[total_len.into()], "buf")
            .map_err(|e| format!("malloc: {e}"))?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| "malloc should return a value".to_string())?
            .into_pointer_value();
        let memcpy_fn = module
            .get_function("memcpy")
            .ok_or_else(|| "missing memcpy declaration".to_string())?;
        builder
            .build_call(
                memcpy_fn,
                &[
                    buf.into(),
                    left_ptr.into(),
                    left_len.into(),
                ],
                "cpy.left",
            )
            .map_err(|e| format!("memcpy left: {e}"))?;
        let left_end = unsafe {
            builder.build_gep(context.i8_type(), buf, &[left_len], "left.end")
        }.map_err(|e| format!("gep left_end: {e}"))?;
        builder
            .build_call(
                memcpy_fn,
                &[
                    left_end.into(),
                    right_ptr.into(),
                    right_len.into(),
                ],
                "cpy.right",
            )
            .map_err(|e| format!("memcpy right: {e}"))?;

        let st = string_type(context);
        let result = st.get_undef();
        let result = builder
            .build_insert_value(result, buf, 0, "res.ptr")
            .map_err(|e| format!("insert ptr: {e}"))?
            .into_struct_value();
        let result = builder
            .build_insert_value(result, total_len, 1, "res.len")
            .map_err(|e| format!("insert len: {e}"))?
            .into_struct_value();
        return Ok(result.into());
    }

    let left_is_float = left.is_float_value();
    let right_is_float = right.is_float_value();
    if left_is_float != right_is_float {
        return Err("cannot mix integer and float in binary operation".to_string());
    }
    if left_is_float || right_is_float {
        let left = left.into_float_value();
        let right = right.into_float_value();
        match op {
            MirBinOp::Add => builder.build_float_add(left, right, "fadd").map(Into::into),
            MirBinOp::Sub => builder.build_float_sub(left, right, "fsub").map(Into::into),
            MirBinOp::Mul => builder.build_float_mul(left, right, "fmul").map(Into::into),
            MirBinOp::Div => builder.build_float_div(left, right, "fdiv").map(Into::into),
            MirBinOp::Eq => builder
                .build_float_compare(FloatPredicate::OEQ, left, right, "feq")
                .map(Into::into),
            MirBinOp::Ne => builder
                .build_float_compare(FloatPredicate::ONE, left, right, "fne")
                .map(Into::into),
            MirBinOp::Lt => builder
                .build_float_compare(FloatPredicate::OLT, left, right, "flt")
                .map(Into::into),
            MirBinOp::Gt => builder
                .build_float_compare(FloatPredicate::OGT, left, right, "fgt")
                .map(Into::into),
            MirBinOp::Le => builder
                .build_float_compare(FloatPredicate::OLE, left, right, "fle")
                .map(Into::into),
            MirBinOp::Ge => builder
                .build_float_compare(FloatPredicate::OGE, left, right, "fge")
                .map(Into::into),
            MirBinOp::Mod | MirBinOp::And | MirBinOp::Or => {
                return Err(format!("unsupported float binary op '{op:?}'"));
            }
        }
        .map_err(|e| format!("failed to build float binop: {e}"))
    } else {
        let left = left.into_int_value();
        let right = right.into_int_value();
        // Normalize widths: FFI bool returns i8 but Axon bool is i1.
        let left_w = left.get_type().get_bit_width();
        let right_w = right.get_type().get_bit_width();
        let (left, right) = if left_w != right_w {
            let target_w = left_w.max(right_w);
            let left = if left_w < target_w {
                builder.build_int_s_extend(left, context.custom_width_int_type(target_w), "l_ext").map_err(|e| format!("extend left: {e}"))?
            } else { left };
            let right = if right_w < target_w {
                builder.build_int_s_extend(right, context.custom_width_int_type(target_w), "r_ext").map_err(|e| format!("extend right: {e}"))?
            } else { right };
            (left, right)
        } else {
            (left, right)
        };
        match op {
            MirBinOp::Add => builder.build_int_add(left, right, "iadd").map(Into::into),
            MirBinOp::Sub => builder.build_int_sub(left, right, "isub").map(Into::into),
            MirBinOp::Mul => builder.build_int_mul(left, right, "imul").map(Into::into),
            MirBinOp::Div => builder
                .build_int_signed_div(left, right, "idiv")
                .map(Into::into),
            MirBinOp::Mod => builder
                .build_int_signed_rem(left, right, "irem")
                .map(Into::into),
            MirBinOp::Eq => builder
                .build_int_compare(IntPredicate::EQ, left, right, "ieq")
                .map(Into::into),
            MirBinOp::Ne => builder
                .build_int_compare(IntPredicate::NE, left, right, "ine")
                .map(Into::into),
            MirBinOp::Lt => builder
                .build_int_compare(IntPredicate::SLT, left, right, "ilt")
                .map(Into::into),
            MirBinOp::Gt => builder
                .build_int_compare(IntPredicate::SGT, left, right, "igt")
                .map(Into::into),
            MirBinOp::Le => builder
                .build_int_compare(IntPredicate::SLE, left, right, "ile")
                .map(Into::into),
            MirBinOp::Ge => builder
                .build_int_compare(IntPredicate::SGE, left, right, "ige")
                .map(Into::into),
            MirBinOp::And => builder.build_and(left, right, "and").map(Into::into),
            MirBinOp::Or => builder.build_or(left, right, "or").map(Into::into),
        }
        .map_err(|e| format!("failed to build int binop: {e}"))
    }
}

fn coerce_to_type<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    value: BasicValueEnum<'ctx>,
    target_ty: &MirType,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
) -> Result<BasicValueEnum<'ctx>, String> {
    let value_type = value.get_type();
    let target_basic = match basic_type(context, target_ty, axon_structs, struct_types) {
        Ok(t) => t,
        Err(_) => return Ok(value),
    };
    if value_type == target_basic {
        return Ok(value);
    }

    if value.is_int_value() && target_basic.is_int_type() {
        let int_val = value.into_int_value();
        let target_int = target_basic.into_int_type();
        let from_bits = int_val.get_type().get_bit_width();
        let to_bits = target_int.get_bit_width();

        if to_bits > from_bits {
            return Ok(builder
                .build_int_s_extend(int_val, target_int, "widen")
                .map_err(|e| format!("int extend: {e}"))?
                .into());
        } else if to_bits < from_bits {
            return Ok(builder
                .build_int_truncate(int_val, target_int, "narrow")
                .map_err(|e| format!("int truncate: {e}"))?
                .into());
        }
    }

    Ok(value)
}

#[allow(clippy::too_many_arguments)]
fn compile_call_target<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    functions: &HashMap<MirCallTarget, FunctionValue<'ctx>>,
    locals: &HashMap<LocalId, (PointerValue<'ctx>, BasicTypeEnum<'ctx>)>,
    local_struct_names: &HashMap<LocalId, String>,
    target: &MirCallTarget,
    args: &[MirExpr],
    foreign_funcs: &ForeignFuncs,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
    owned_locals: &HashSet<u32>,
    string_literal_locals: &HashSet<u32>,
) -> Result<Option<BasicValueEnum<'ctx>>, String> {
    match target {
        MirCallTarget::Builtin { name } => match name.as_str() {
            "print" => {
                let arg = args
                    .first()
                    .ok_or_else(|| "print requires one argument".to_string())?;
                let value = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    arg,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                let is_owned = is_expr_owned(arg, owned_locals, string_literal_locals);
                compile_print(context, builder, module, value, is_owned)?;
                Ok(None)
            }
            "assert" => {
                let arg = args
                    .first()
                    .ok_or_else(|| "assert requires one argument".to_string())?;
                let cond_val = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    arg,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                if !cond_val.is_int_value() {
                    return Err("assert argument must be an integer value".to_string());
                }
                let cond =
                    coerce_condition_to_i1(builder, cond_val.into_int_value())?;
                build_assert(context, builder, module, cond)?;
                Ok(None)
            }
            "panic" => {
                let arg = args
                    .first()
                    .ok_or_else(|| "panic requires one argument".to_string())?;
                let msg = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    arg,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                build_panic(context, builder, module, msg)?;
                Ok(None)
            }
            // `input` calls `getline` which allocates via glibc (heap/malloc).
            // The returned string struct wraps the getline buffer pointer.
            // Ownership tracking: when the result is stored to a local marked as
            // CanonicalOwner in owned_locals, emit_builtin_consume will call `free`
            // on the pointer when the value is consumed by another builtin (print, etc.).
            // No special cleanup needed here; the ownership plumbing handles it.
            "input" => {
                let i8_ptr = context.ptr_type(inkwell::AddressSpace::default());

                let stdin = module
                    .get_global("stdin")
                    .ok_or_else(|| "missing stdin global".to_string())?
                    .as_pointer_value();

                let lineptr_ptr = builder
                    .build_alloca(i8_ptr, "lineptr_ptr")
                    .map_err(|e| format!("failed to allocate lineptr_ptr: {e}"))?;
                let n_ptr = builder
                    .build_alloca(context.i64_type(), "n_ptr")
                    .map_err(|e| format!("failed to allocate n_ptr: {e}"))?;

                builder
                    .build_store(lineptr_ptr, i8_ptr.const_null())
                    .map_err(|e| format!("failed to store null to lineptr_ptr: {e}"))?;
                builder
                    .build_store(n_ptr, context.i64_type().const_zero())
                    .map_err(|e| format!("failed to store zero to n_ptr: {e}"))?;

                let getline = module
                    .get_function("getline")
                    .ok_or_else(|| "missing getline declaration".to_string())?;
                builder
                    .build_call(
                        getline,
                        &[lineptr_ptr.into(), n_ptr.into(), stdin.into()],
                        "getline_call",
                    )
                    .map_err(|e| format!("failed to call getline: {e}"))?;

                let lineptr = builder
                    .build_load(i8_ptr, lineptr_ptr, "lineptr")
                    .map_err(|e| format!("failed to load lineptr: {e}"))?
                    .into_pointer_value();

                let strlen_fn = module
                    .get_function("strlen")
                    .ok_or_else(|| "missing strlen declaration".to_string())?;
                let len_val = builder
                    .build_call(strlen_fn, &[lineptr.into()], "strlen_call")
                    .map_err(|e| format!("failed to call strlen: {e}"))?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| "strlen should return a value".to_string())?
                    .into_int_value();

                let st = string_type(context);
                let undef = st.get_undef();
                let with_ptr = builder
                    .build_insert_value(undef, lineptr, 0, "str_ptr")
                    .map_err(|e| format!("failed to insert string ptr: {e}"))?
                    .into_struct_value();
                let struct_val = builder
                    .build_insert_value(with_ptr, len_val, 1, "str_len")
                    .map_err(|e| format!("failed to insert string len: {e}"))?
                    .into_struct_value()
                    .into();

                Ok(Some(struct_val))
            }
            "assert_eq" => {
                let left = args
                    .first()
                    .ok_or_else(|| "assert_eq requires two arguments".to_string())?;
                let right = args
                    .get(1)
                    .ok_or_else(|| "assert_eq requires two arguments".to_string())?;
                let left_val = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    left,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                let right_val = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    right,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                let left_owned = is_expr_owned(left, owned_locals, string_literal_locals);
                let right_owned = is_expr_owned(right, owned_locals, string_literal_locals);
                build_assert_eq(
                    context,
                    builder,
                    module,
                    left_val,
                    right_val,
                    left_owned,
                    right_owned,
                )?;
                Ok(None)
            }
            "assert_ne" => {
                let left = args
                    .first()
                    .ok_or_else(|| "assert_ne requires two arguments".to_string())?;
                let right = args
                    .get(1)
                    .ok_or_else(|| "assert_ne requires two arguments".to_string())?;
                let left_val = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    left,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                let right_val = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    right,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;
                let left_owned = is_expr_owned(left, owned_locals, string_literal_locals);
                let right_owned = is_expr_owned(right, owned_locals, string_literal_locals);
                build_assert_ne(
                    context,
                    builder,
                    module,
                    left_val,
                    right_val,
                    left_owned,
                    right_owned,
                )?;
                Ok(None)
            }
            _ => Err(format!("unknown builtin '{}'", name)),
        },
        MirCallTarget::ModuleEntry { .. } => {
            let callee = functions.get(target).copied().ok_or_else(|| {
                format!("missing function declaration for target {:?}", target)
            })?;
            let call_args = args
                .iter()
                .map(|arg| {
                    compile_expr(
                        context,
                        builder,
                        module,
                        functions,
                        locals,
                        local_struct_names,
                        arg,
                        foreign_funcs,
                        axon_structs,
                        struct_types,
                        owned_locals,
                        string_literal_locals,
                    )
                    .map(BasicMetadataValueEnum::from)
                })
                .collect::<Result<Vec<_>, _>>()?;
            let call = builder
                .build_call(callee, &call_args, "call")
                .map_err(|e| format!("failed to build call to '{:?}': {e}", target))?;
            Ok(call.try_as_basic_value().basic())
        }
        MirCallTarget::Foreign { symbol, lib: _ } => {
            let callee = module
                .get_function(symbol)
                .ok_or_else(|| format!("foreign function '{}' not declared", symbol))?;

            let is_string_return = foreign_funcs.is_string_return(symbol);
            let param_types = foreign_funcs.get_param_types(symbol);
            let is_go = foreign_funcs.is_go(symbol);

            let mut call_args: Vec<BasicMetadataValueEnum<'ctx>> = Vec::new();
            for (arg_idx, arg) in args.iter().enumerate() {
                let val = compile_expr(
                    context,
                    builder,
                    module,
                    functions,
                    locals,
                    local_struct_names,
                    arg,
                    foreign_funcs,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    string_literal_locals,
                )?;

                let param_ty = param_types.and_then(|p| p.get(arg_idx).cloned());
                let is_string_param = param_ty
                    .map(|ty| matches!(ty, MirType::String))
                    .unwrap_or(false);

                if val.is_struct_value() && is_string_param {
                    let str_struct = val.into_struct_value();
                    let str_ptr = builder
                        .build_extract_value(str_struct, 0, "str_ptr")
                        .map_err(|e| {
                            format!("failed to extract string ptr for foreign arg: {e}")
                        })?;
                    let str_len_i64_val = builder
                        .build_extract_value(str_struct, 1, "str_len_i64")
                        .map_err(|e| {
                            format!("failed to extract string len for foreign arg: {e}")
                        })?;
                    call_args.push(BasicMetadataValueEnum::from(str_ptr));
                    if is_go {
                        let str_len = builder
                            .build_int_truncate(
                                str_len_i64_val.into_int_value(),
                                context.i32_type(),
                                "str_len",
                            )
                            .map_err(|e| format!("failed to truncate string len: {e}"))?;
                        call_args.push(BasicMetadataValueEnum::from(str_len));
                    } else {
                        call_args.push(BasicMetadataValueEnum::from(
                            str_len_i64_val.into_int_value(),
                        ));
                    }
                } else if val.is_struct_value() {
                    let ptr = builder
                        .build_extract_value(val.into_struct_value(), 0, "str_ptr")
                        .map_err(|e| format!("failed to extract ptr for foreign arg: {e}"))?;
                    call_args.push(BasicMetadataValueEnum::from(ptr));
                } else {
                    call_args.push(BasicMetadataValueEnum::from(val));
                }
            }

            let buf_ptr_val = if is_string_return {
                // Always allocate via malloc so the ownership pipeline can free it.
                // Stack-allocated buffers would leak when the ownership pipeline
                // calls free() on them at cleanup.
                let malloc_fn = module
                    .get_function("malloc")
                    .ok_or_else(|| "missing malloc declaration".to_string())?;
                let buf_size: u64 = 4096;
                let buf_call = builder
                    .build_call(
                        malloc_fn,
                        &[context.i64_type().const_int(buf_size, false).into()],
                        "str_buf",
                    )
                    .map_err(|e| format!("failed to build malloc for string buffer: {e}"))?;
                let buf_ptr = buf_call
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| "malloc returned void".to_string())?
                    .into_pointer_value();

                let user_args_count = call_args.len();
                call_args.push(buf_ptr.into());
                if is_go {
                    call_args.push(context.i32_type().const_int(buf_size, false).into());
                } else {
                    call_args.push(context.i64_type().const_int(buf_size, false).into());
                }
                Some((buf_ptr, user_args_count))
            } else {
                None
            };

            let call = builder
                .build_call(callee, &call_args, "foreign_call")
                .map_err(|e| format!("failed to build foreign call to '{}': {e}", symbol))?;
            let result = call.try_as_basic_value().basic();

            if is_string_return && let Some(val) = result {
                let len_i32 = val.into_int_value();
                let (initial_buf_ptr, user_args_count) = buf_ptr_val.unwrap();
                let initial_len_i64 = builder
                    .build_int_s_extend(len_i32, context.i64_type(), "str_len_ext")
                    .map_err(|e| format!("failed to extend string length: {e}"))?;

                let current_block = builder
                    .get_insert_block()
                    .ok_or_else(|| "no insert block".to_string())?;
                let fn_value = current_block
                    .get_parent()
                    .ok_or_else(|| "no parent function".to_string())?;

                let overflow_block = context.append_basic_block(fn_value, "str_overflow");
                let merge_block = context.append_basic_block(fn_value, "str_merge");

                let i32_zero = context.i32_type().const_int(0, false);
                let is_overflow_cmp = builder
                    .build_int_compare(IntPredicate::SLT, len_i32, i32_zero, "is_overflow")
                    .map_err(|e| format!("failed to build overflow cmp: {e}"))?;
                builder
                    .build_conditional_branch(is_overflow_cmp, overflow_block, merge_block)
                    .map_err(|e| format!("failed to build overflow branch: {e}"))?;

                builder.position_at_end(overflow_block);

                let malloc_fn = module
                    .get_function("malloc")
                    .ok_or_else(|| "missing malloc declaration".to_string())?;
                let retry_buf_size: u64 = 8192;
                let retry_buf_call = builder
                    .build_call(
                        malloc_fn,
                        &[context.i64_type().const_int(retry_buf_size, false).into()],
                        "heap_buf",
                    )
                    .map_err(|e| format!("failed to build malloc call: {e}"))?;
                let retry_buf = retry_buf_call
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| "malloc returned void".to_string())?
                    .into_pointer_value();

                let mut retry_args: Vec<BasicMetadataValueEnum<'ctx>> =
                    call_args[..user_args_count].to_vec();
                retry_args.push(retry_buf.into());
                if is_go {
                    retry_args.push(context.i32_type().const_int(retry_buf_size, false).into());
                } else {
                    retry_args.push(context.i64_type().const_int(retry_buf_size, false).into());
                }

                let retry_call = builder
                    .build_call(callee, &retry_args, "retry_foreign_call")
                    .map_err(|e| {
                        format!("failed to build retry foreign call to '{}': {e}", symbol)
                    })?;
                let retry_result = retry_call.try_as_basic_value().basic();

                let retry_len_i32 = retry_result
                    .map(|v| v.into_int_value())
                    .unwrap_or_else(|| context.i32_type().const_int(0, false));

                let retry_zero = context.i32_type().const_int(0, false);
                let still_overflow = builder
                    .build_int_compare(
                        IntPredicate::SLT,
                        retry_len_i32,
                        retry_zero,
                        "still_overflow",
                    )
                    .map_err(|e| format!("failed to build retry overflow cmp: {e}"))?;
                let safe_retry_len = builder
                    .build_select(still_overflow, retry_zero, retry_len_i32, "safe_retry_len")
                    .map_err(|e| format!("failed to build safe retry len: {e}"))?
                    .into_int_value();
                let retry_len_i64 = builder
                    .build_int_s_extend(safe_retry_len, context.i64_type(), "retry_str_len_ext")
                    .map_err(|e| format!("failed to extend retry string length: {e}"))?;

                builder
                    .build_unconditional_branch(merge_block)
                    .map_err(|e| format!("failed to build branch to merge: {e}"))?;
                let overflow_end_block = builder
                    .get_insert_block()
                    .ok_or_else(|| "no insert block after overflow".to_string())?;

                builder.position_at_end(merge_block);

                // Both initial_buf_ptr (from initial malloc) and retry_buf (from overflow
                // malloc) are heap-allocated, so the ownership pipeline can free either.
                let ptr_phi = builder
                    .build_phi(
                        context.ptr_type(inkwell::AddressSpace::default()),
                        "final_str_ptr",
                    )
                    .map_err(|e| format!("failed to build ptr phi: {e}"))?;
                let initial_buf_bve: BasicValueEnum<'ctx> = initial_buf_ptr.into();
                let retry_buf_bve: BasicValueEnum<'ctx> = retry_buf.into();
                ptr_phi.add_incoming(&[
                    (&initial_buf_bve, current_block),
                    (&retry_buf_bve, overflow_end_block),
                ]);

                let len_phi = builder
                    .build_phi(context.i64_type(), "final_str_len")
                    .map_err(|e| format!("failed to build len phi: {e}"))?;
                let initial_len_bve: BasicValueEnum<'ctx> = initial_len_i64.into();
                let retry_len_bve: BasicValueEnum<'ctx> = retry_len_i64.into();
                len_phi.add_incoming(&[
                    (&initial_len_bve, current_block),
                    (&retry_len_bve, overflow_end_block),
                ]);

                let st = string_type(context);
                let undef = st.get_undef();
                let with_ptr = builder
                    .build_insert_value(undef, ptr_phi.as_basic_value(), 0, "str_ptr")
                    .map_err(|e| format!("failed to insert string ptr: {e}"))?
                    .into_struct_value();
                let struct_val = builder
                    .build_insert_value(with_ptr, len_phi.as_basic_value(), 1, "str_len")
                    .map_err(|e| format!("failed to insert string len: {e}"))?
                    .into_struct_value()
                    .into();
                return Ok(Some(struct_val));
            }

            if let (Some(ret_ty), Some(basic_val)) =
                (foreign_funcs.mir_return_ty(symbol.as_str()), result)
            {
                let coerced = coerce_to_type(
                    context,
                    builder,
                    basic_val,
                    ret_ty,
                    axon_structs,
                    struct_types,
                )?;
                return Ok(Some(coerced));
            }

            Ok(result)
        }
    }
}

fn compile_print<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    value: BasicValueEnum<'ctx>,
    is_owned: bool,
) -> Result<(), String> {
    if value.is_struct_value() {
        // Extract ptr and len from string struct
        let str_ptr = builder
            .build_extract_value(value.into_struct_value(), 0, "str_ptr")
            .map_err(|e| format!("failed to extract string ptr: {e}"))?;
        let str_len = builder
            .build_extract_value(value.into_struct_value(), 1, "str_len")
            .map_err(|e| format!("failed to extract string len: {e}"))?;

        // Use printf with %.*s format for length-aware printing
        let printf = module
            .get_function("printf")
            .ok_or_else(|| "missing printf declaration".to_string())?;

        // Create format string: "%.*s\n"
        let format_str = "%.*s\n";
        let format_ptr = builder
            .build_global_string_ptr(format_str, "print_str_format")
            .map_err(|e| format!("failed to build format string: {e}"))?;

        builder
            .build_call(
                printf,
                &[
                    format_ptr.as_pointer_value().into(),
                    str_len.into(),
                    str_ptr.into_pointer_value().into(),
                ],
                "printf_str",
            )
            .map_err(|e| format!("failed to build printf call: {e}"))?;

        let fflush = module
            .get_function("fflush")
            .ok_or_else(|| "missing fflush declaration".to_string())?;
        let null_ptr = context
            .ptr_type(inkwell::AddressSpace::default())
            .const_null();
        builder
            .build_call(fflush, &[null_ptr.into()], "fflush_all")
            .map_err(|e| format!("failed to build fflush: {e}"))?;

        // Consume the string value after printing if it's owned
        emit_builtin_consume(context, builder, module, value, &MirType::String, is_owned)?;
        return Ok(());
    }

    let printf = module
        .get_function("printf")
        .ok_or_else(|| "missing printf declaration".to_string())?;
    let (format_str, arg): (&str, BasicMetadataValueEnum<'ctx>) = if value.is_float_value() {
        ("%f\n", value.into_float_value().into())
    } else {
        let int_value = value.into_int_value();
        if int_value.get_type().get_bit_width() == 1 {
            let text = if int_value.is_const() {
                if int_value.get_zero_extended_constant() == Some(1) {
                    "true"
                } else {
                    "false"
                }
            } else {
                return build_dynamic_bool_print(context, builder, module, int_value);
            };
            let puts = module
                .get_function("puts")
                .ok_or_else(|| "missing puts declaration".to_string())?;
            let text_ptr = builder
                .build_global_string_ptr(text, "bool_text")
                .map_err(|e| format!("failed to build bool string: {e}"))?;
            builder
                .build_call(puts, &[text_ptr.as_pointer_value().into()], "puts_bool")
                .map_err(|e| format!("failed to build bool puts call: {e}"))?;
            // Bools are scalars, no cleanup needed
            return Ok(());
        }
        ("%lld\n", int_value.into())
    };

    let format_ptr = builder
        .build_global_string_ptr(format_str, "fmt")
        .map_err(|e| format!("failed to build format string: {e}"))?;
    builder
        .build_call(
            printf,
            &[format_ptr.as_pointer_value().into(), arg],
            "printf_call",
        )
        .map_err(|e| format!("failed to build printf call: {e}"))?;

    // Consume the value after printing if it's owned (no-op for scalars)
    let value_type = if value.is_float_value() {
        MirType::Float(FloatWidth::F64)
    } else if value.is_int_value() {
        let width = value.into_int_value().get_type().get_bit_width();
        if width == 1 {
            MirType::Bool
        } else {
            MirType::Int(IntWidth::I32)
        }
    } else {
        // Unknown type, skip cleanup
        return Ok(());
    };
    emit_builtin_consume(context, builder, module, value, &value_type, is_owned)?;
    Ok(())
}

fn build_dynamic_bool_print<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    value: inkwell::values::IntValue<'ctx>,
) -> Result<(), String> {
    let current_block = builder
        .get_insert_block()
        .ok_or_else(|| "missing current insertion block".to_string())?;
    let function = current_block
        .get_parent()
        .ok_or_else(|| "missing parent function for bool print".to_string())?;
    let then_block = context.append_basic_block(function, "bool_true");
    let else_block = context.append_basic_block(function, "bool_false");
    let end_block = context.append_basic_block(function, "bool_end");
    let value = coerce_condition_to_i1(builder, value)?;
    builder
        .build_conditional_branch(value, then_block, else_block)
        .map_err(|e| format!("failed to build bool branch: {e}"))?;

    let puts = module
        .get_function("puts")
        .ok_or_else(|| "missing puts declaration".to_string())?;

    builder.position_at_end(then_block);
    let true_ptr = builder
        .build_global_string_ptr("true", "true_text")
        .map_err(|e| format!("failed to build true string: {e}"))?;
    builder
        .build_call(puts, &[true_ptr.as_pointer_value().into()], "puts_true")
        .map_err(|e| format!("failed to build true puts call: {e}"))?;
    builder
        .build_unconditional_branch(end_block)
        .map_err(|e| format!("failed to close true bool branch: {e}"))?;

    builder.position_at_end(else_block);
    let false_ptr = builder
        .build_global_string_ptr("false", "false_text")
        .map_err(|e| format!("failed to build false string: {e}"))?;
    builder
        .build_call(puts, &[false_ptr.as_pointer_value().into()], "puts_false")
        .map_err(|e| format!("failed to build false puts call: {e}"))?;
    builder
        .build_unconditional_branch(end_block)
        .map_err(|e| format!("failed to close false bool branch: {e}"))?;

    builder.position_at_end(end_block);
    Ok(())
}

fn build_assert<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    cond: inkwell::values::IntValue<'ctx>,
) -> Result<(), String> {
    let current_block = builder
        .get_insert_block()
        .ok_or_else(|| "missing current insertion block".to_string())?;
    let function = current_block
        .get_parent()
        .ok_or_else(|| "missing parent function for assert".to_string())?;
    let pass_block = context.append_basic_block(function, "assert_ok");
    let fail_block = context.append_basic_block(function, "assert_fail");

    builder
        .build_conditional_branch(cond, pass_block, fail_block)
        .map_err(|e| format!("failed to build assert branch: {e}"))?;

    builder.position_at_end(fail_block);
    let puts = module
        .get_function("puts")
        .ok_or_else(|| "missing puts declaration".to_string())?;
    let abort = module
        .get_function("abort")
        .ok_or_else(|| "missing abort declaration".to_string())?;
    let fail_msg = builder
        .build_global_string_ptr("assertion failed", "assert_msg")
        .map_err(|e| format!("failed to build assert message: {e}"))?;
    builder
        .build_call(puts, &[fail_msg.as_pointer_value().into()], "puts_assert")
        .map_err(|e| format!("failed to build assert message call: {e}"))?;
    builder
        .build_call(abort, &[], "abort")
        .map_err(|e| format!("failed to build abort call: {e}"))?;
    builder
        .build_unreachable()
        .map_err(|e| format!("failed to build assert unreachable: {e}"))?;

    builder.position_at_end(pass_block);
    Ok(())
}

/// Consume a builtin argument according to its ownership classification.
///
/// This function implements the Phase 1 builtin ownership contract:
/// - If owned non-aggregate: the value is consumed and freed after use.
/// - If pointer: the value is read only, no dealloc.
///
/// In Phase 1, this only applies to string types. Scalars (i32, bool, f64)
/// don't need deallocation. Builtins handle normal scalar/string values, not whole structs.
///
/// # Arguments
///
/// * `_context` - LLVM context (unused but kept for API consistency)
/// * `builder` - LLVM IR builder for generating instructions
/// * `module` - LLVM module containing function declarations
/// * `value` - The LLVM value being consumed
/// * `value_type` - The MIR type of the value
/// * `is_owned` - If true, the value is a canonical owner and should be freed.
///   If false, the value is a pointer and should NOT be freed.
///
/// # Ownership Model
///
/// Per the Phase 1 design spec:
/// - Builtins are terminal consumers that may free owned inputs
/// - Only builtins call `dealloc`; user-defined functions never free directly
/// - Builtins must handle both pointer and owned inputs
/// - `dealloc` is called only for owned non-aggregate inputs (strings in Phase 1)
///
/// # Current Status
///
/// For Phase 1 implementation, ownership information from the typechecker's
/// `OwnershipSummary` is not yet plumbed through to codegen. Therefore, this
/// helper takes a conservative approach:
/// - When `is_owned=false` (default), no free is generated (safe)
/// - When `is_owned=true`, free is generated for owned strings
///
/// # Future Integration
///
/// Once ownership is plumbed through, usage should look like:
///
/// ```rust,ignore
/// // In compile_stmt or compile_call_target, after getting the ownership info:
/// let is_owned = ownership_summaries
///     .get(&local_id)
///     .map(|summary| summary.classification == OwnershipClassification::CanonicalOwner)
///     .unwrap_or(false);  // Conservative: assume pointer if unknown
///
/// // After using the value in a builtin:
/// emit_builtin_consume(context, builder, module, value, &mir_type, is_owned)?;
/// ```
///
/// # Examples
///
/// Owned string - freed after use:
/// ```rust,ignore
/// let s = "hello";  // s is canonical owner
/// print(s);         // print consumes s, should free
/// ```
/// Codegen (when is_owned=true):
/// 1. Print the string
/// 2. Call `free(s.ptr)` to deallocate
///
/// Pointer string - NOT freed:
/// ```rust,ignore
/// let s = "hello";
/// let t = s;        // s becomes pointer, t is owner
/// print(s);         // print reads pointer, should NOT free
/// ```
/// Codegen (when is_owned=false):
/// 1. Print the string
/// 2. No free call (t owns the data)
fn emit_builtin_consume<'ctx>(
    _context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    value: BasicValueEnum<'ctx>,
    value_type: &MirType,
    is_owned: bool,
) -> Result<(), String> {
    // If not owned, just read without dealloc
    if !is_owned {
        return Ok(());
    }

    if let MirType::String = value_type {
        let str_ptr = builder
            .build_extract_value(value.into_struct_value(), 0, "str_ptr")
            .map_err(|e| format!("failed to extract string ptr for free: {e}"))?;
        let free_fn = module
            .get_function("free")
            .ok_or_else(|| "missing free declaration".to_string())?;
        builder
            .build_call(free_fn, &[str_ptr.into()], "free_str")
            .map_err(|e| format!("failed to build free call: {e}"))?;
    }

    Ok(())
}

fn build_assert_eq<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    left: BasicValueEnum<'ctx>,
    right: BasicValueEnum<'ctx>,
    left_owned: bool,
    right_owned: bool,
) -> Result<(), String> {
    let current_block = builder
        .get_insert_block()
        .ok_or_else(|| "missing current insertion block".to_string())?;
    let function = current_block
        .get_parent()
        .ok_or_else(|| "missing parent function for assert_eq".to_string())?;
    let pass_block = context.append_basic_block(function, "assert_eq_ok");
    let fail_block = context.append_basic_block(function, "assert_eq_fail");

    // Detect string struct values: {ptr, len} with exactly 2 fields
    let left_is_string =
        left.is_struct_value() && left.into_struct_value().get_type().count_fields() == 2;
    let right_is_string =
        right.is_struct_value() && right.into_struct_value().get_type().count_fields() == 2;
    let both_strings = left_is_string && right_is_string;

    let eq = if left.is_int_value() && right.is_int_value() {
        builder
            .build_int_compare(
                IntPredicate::EQ,
                left.into_int_value(),
                right.into_int_value(),
                "eq",
            )
            .map_err(|e| format!("failed to build eq comparison: {e}"))?
    } else if left.is_float_value() && right.is_float_value() {
        builder
            .build_float_compare(
                FloatPredicate::OEQ,
                left.into_float_value(),
                right.into_float_value(),
                "eq",
            )
            .map_err(|e| format!("failed to build float eq: {e}"))?
    } else if both_strings {
        // String content comparison using memcmp, not pointer identity
        let left_struct = left.into_struct_value();
        let right_struct = right.into_struct_value();

        let left_ptr = builder
            .build_extract_value(left_struct, 0, "str_ptr_l")
            .map_err(|e| format!("failed to extract left string ptr: {e}"))?
            .into_pointer_value();
        let left_len = builder
            .build_extract_value(left_struct, 1, "str_len_l")
            .map_err(|e| format!("failed to extract left string len: {e}"))?
            .into_int_value();
        let right_ptr = builder
            .build_extract_value(right_struct, 0, "str_ptr_r")
            .map_err(|e| format!("failed to extract right string ptr: {e}"))?
            .into_pointer_value();
        let right_len = builder
            .build_extract_value(right_struct, 1, "str_len_r")
            .map_err(|e| format!("failed to extract right string len: {e}"))?
            .into_int_value();

        // Fast path: compare lengths first
        let len_eq = builder
            .build_int_compare(IntPredicate::EQ, left_len, right_len, "len_eq")
            .map_err(|e| format!("failed to compare string lengths: {e}"))?;

        // If lengths differ, strings are not equal -> skip content comparison
        let content_cmp_block = context.append_basic_block(function, "str_content_cmp");
        let len_diff_block = context.append_basic_block(function, "str_len_diff");
        let merge_block = context.append_basic_block(function, "str_eq_merge");

        builder
            .build_conditional_branch(len_eq, content_cmp_block, len_diff_block)
            .map_err(|e| format!("failed to build len check branch: {e}"))?;

        // Lengths differ: not equal
        builder.position_at_end(len_diff_block);
        builder
            .build_unconditional_branch(merge_block)
            .map_err(|e| format!("failed to build branch to merge: {e}"))?;
        let len_diff_end = builder
            .get_insert_block()
            .ok_or_else(|| "no insert block".to_string())?;

        // Lengths equal: compare content with memcmp
        builder.position_at_end(content_cmp_block);
        let memcmp_fn = module
            .get_function("memcmp")
            .ok_or_else(|| "missing memcmp declaration".to_string())?;
        let memcmp_result = builder
            .build_call(
                memcmp_fn,
                &[left_ptr.into(), right_ptr.into(), left_len.into()],
                "memcmp_result",
            )
            .map_err(|e| format!("failed to build memcmp call: {e}"))?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| "memcmp should return a value".to_string())?
            .into_int_value();
        let content_eq = builder
            .build_int_compare(
                IntPredicate::EQ,
                memcmp_result,
                context.i32_type().const_int(0, false),
                "content_eq",
            )
            .map_err(|e| format!("failed to compare memcmp result: {e}"))?;

        builder
            .build_unconditional_branch(merge_block)
            .map_err(|e| format!("failed to build branch to merge: {e}"))?;
        let content_cmp_end = builder
            .get_insert_block()
            .ok_or_else(|| "no insert block".to_string())?;

        // Merge: phi-merge the equality result
        builder.position_at_end(merge_block);
        let phi = builder
            .build_phi(context.bool_type(), "str_eq_result")
            .map_err(|e| format!("failed to build str eq phi: {e}"))?;
        let false_val = context.bool_type().const_int(0, false);
        phi.add_incoming(&[(&false_val, len_diff_end)]);
        phi.add_incoming(&[(&content_eq, content_cmp_end)]);

        phi.as_basic_value().into_int_value()
    } else if left.is_pointer_value() && right.is_pointer_value() {
        builder
            .build_int_compare(
                IntPredicate::EQ,
                left.into_pointer_value(),
                right.into_pointer_value(),
                "eq",
            )
            .map_err(|e| format!("failed to build ptr eq comparison: {e}"))?
    } else {
        return Err("assert_eq: unsupported operand types for comparison".to_string());
    };

    builder
        .build_conditional_branch(eq, pass_block, fail_block)
        .map_err(|e| format!("failed to build assert_eq branch: {e}"))?;

    // Fail block: print diagnostic and abort
    builder.position_at_end(fail_block);
    let abort_fn = module
        .get_function("abort")
        .ok_or_else(|| "missing abort declaration".to_string())?;

    if left.is_int_value() && right.is_int_value() {
        let printf = module
            .get_function("printf")
            .ok_or_else(|| "missing printf declaration".to_string())?;
        let fmt = builder
            .build_global_string_ptr(
                "assertion failed: expected %lld, got %lld\n",
                "assert_eq_fmt",
            )
            .map_err(|e| format!("failed to build assert_eq format string: {e}"))?;
        builder
            .build_call(
                printf,
                &[
                    fmt.as_pointer_value().into(),
                    left.into_int_value().into(),
                    right.into_int_value().into(),
                ],
                "printf_assert_eq",
            )
            .map_err(|e| format!("failed to build assert_eq printf: {e}"))?;
    } else if left.is_float_value() && right.is_float_value() {
        let printf = module
            .get_function("printf")
            .ok_or_else(|| "missing printf declaration".to_string())?;
        let fmt = builder
            .build_global_string_ptr("assertion failed: expected %f, got %f\n", "assert_eq_fmt")
            .map_err(|e| format!("failed to build assert_eq format string: {e}"))?;
        builder
            .build_call(
                printf,
                &[
                    fmt.as_pointer_value().into(),
                    left.into_float_value().into(),
                    right.into_float_value().into(),
                ],
                "printf_assert_eq",
            )
            .map_err(|e| format!("failed to build assert_eq printf: {e}"))?;
    } else {
        // String or pointer comparison failure
        let printf = module
            .get_function("printf")
            .ok_or_else(|| "missing printf declaration".to_string())?;
        let fmt = builder
            .build_global_string_ptr("assertion failed: values not equal\n", "assert_eq_fmt")
            .map_err(|e| format!("failed to build assert_eq format string: {e}"))?;
        builder
            .build_call(printf, &[fmt.as_pointer_value().into()], "printf_assert_eq")
            .map_err(|e| format!("failed to build assert_eq printf: {e}"))?;
    }
    builder
        .build_call(abort_fn, &[], "abort")
        .map_err(|e| format!("failed to build abort call: {e}"))?;
    builder
        .build_unreachable()
        .map_err(|e| format!("failed to build unreachable: {e}"))?;

    // Pass block: consume owned string arguments after comparison succeeds
    builder.position_at_end(pass_block);
    if both_strings {
        emit_builtin_consume(context, builder, module, left, &MirType::String, left_owned)?;
        emit_builtin_consume(
            context,
            builder,
            module,
            right,
            &MirType::String,
            right_owned,
        )?;
    }
    Ok(())
}

fn build_assert_ne<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    left: BasicValueEnum<'ctx>,
    right: BasicValueEnum<'ctx>,
    left_owned: bool,
    right_owned: bool,
) -> Result<(), String> {
    let current_block = builder
        .get_insert_block()
        .ok_or_else(|| "missing current insertion block".to_string())?;
    let function = current_block
        .get_parent()
        .ok_or_else(|| "missing parent function for assert_ne".to_string())?;
    let pass_block = context.append_basic_block(function, "assert_ne_ok");
    let fail_block = context.append_basic_block(function, "assert_ne_fail");

    // Detect string struct values: {ptr, len} with exactly 2 fields
    let left_is_string =
        left.is_struct_value() && left.into_struct_value().get_type().count_fields() == 2;
    let right_is_string =
        right.is_struct_value() && right.into_struct_value().get_type().count_fields() == 2;
    let both_strings = left_is_string && right_is_string;

    // For assert_ne, ne = !eq, so we build eq first and invert
    let ne = if left.is_int_value() && right.is_int_value() {
        builder
            .build_int_compare(
                IntPredicate::NE,
                left.into_int_value(),
                right.into_int_value(),
                "ne",
            )
            .map_err(|e| format!("failed to build ne comparison: {e}"))?
    } else if left.is_float_value() && right.is_float_value() {
        builder
            .build_float_compare(
                FloatPredicate::ONE,
                left.into_float_value(),
                right.into_float_value(),
                "ne",
            )
            .map_err(|e| format!("failed to build float ne: {e}"))?
    } else if both_strings {
        // String content comparison using memcmp, then invert for ne
        let left_struct = left.into_struct_value();
        let right_struct = right.into_struct_value();

        let left_ptr = builder
            .build_extract_value(left_struct, 0, "str_ptr_l")
            .map_err(|e| format!("failed to extract left string ptr: {e}"))?
            .into_pointer_value();
        let left_len = builder
            .build_extract_value(left_struct, 1, "str_len_l")
            .map_err(|e| format!("failed to extract left string len: {e}"))?
            .into_int_value();
        let right_ptr = builder
            .build_extract_value(right_struct, 0, "str_ptr_r")
            .map_err(|e| format!("failed to extract right string ptr: {e}"))?
            .into_pointer_value();
        let right_len = builder
            .build_extract_value(right_struct, 1, "str_len_r")
            .map_err(|e| format!("failed to extract right string len: {e}"))?
            .into_int_value();

        // Fast path: compare lengths first
        let len_eq = builder
            .build_int_compare(IntPredicate::EQ, left_len, right_len, "len_eq")
            .map_err(|e| format!("failed to compare string lengths: {e}"))?;

        // If lengths differ, strings are different -> pass for assert_ne
        let content_cmp_block = context.append_basic_block(function, "str_content_cmp");
        let len_diff_block = context.append_basic_block(function, "str_len_diff");
        let merge_block = context.append_basic_block(function, "str_ne_merge");

        builder
            .build_conditional_branch(len_eq, content_cmp_block, len_diff_block)
            .map_err(|e| format!("failed to build len check branch: {e}"))?;

        // Lengths differ: not equal, so ne = true
        builder.position_at_end(len_diff_block);
        builder
            .build_unconditional_branch(merge_block)
            .map_err(|e| format!("failed to build branch to merge: {e}"))?;
        let len_diff_end = builder
            .get_insert_block()
            .ok_or_else(|| "no insert block".to_string())?;

        // Lengths equal: compare content with memcmp
        builder.position_at_end(content_cmp_block);
        let memcmp_fn = module
            .get_function("memcmp")
            .ok_or_else(|| "missing memcmp declaration".to_string())?;
        let memcmp_result = builder
            .build_call(
                memcmp_fn,
                &[left_ptr.into(), right_ptr.into(), left_len.into()],
                "memcmp_result",
            )
            .map_err(|e| format!("failed to build memcmp call: {e}"))?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| "memcmp should return a value".to_string())?
            .into_int_value();
        // content_eq: memcmp == 0 means equal
        let content_eq = builder
            .build_int_compare(
                IntPredicate::EQ,
                memcmp_result,
                context.i32_type().const_int(0, false),
                "content_eq",
            )
            .map_err(|e| format!("failed to compare memcmp result: {e}"))?;
        // ne = !eq: strings are different if content is not equal
        let content_ne = builder
            .build_not(content_eq, "content_ne")
            .map_err(|e| format!("failed to invert content_eq: {e}"))?;

        builder
            .build_unconditional_branch(merge_block)
            .map_err(|e| format!("failed to build branch to merge: {e}"))?;
        let content_cmp_end = builder
            .get_insert_block()
            .ok_or_else(|| "no insert block".to_string())?;

        // Merge: phi-merge the ne result
        // If lengths differ: ne=true; if lengths equal: ne=content_ne
        builder.position_at_end(merge_block);
        let phi = builder
            .build_phi(context.bool_type(), "str_ne_result")
            .map_err(|e| format!("failed to build str ne phi: {e}"))?;
        let true_val = context.bool_type().const_int(1, false);
        phi.add_incoming(&[(&true_val, len_diff_end)]);
        phi.add_incoming(&[(&content_ne, content_cmp_end)]);

        phi.as_basic_value().into_int_value()
    } else if left.is_pointer_value() && right.is_pointer_value() {
        builder
            .build_int_compare(
                IntPredicate::NE,
                left.into_pointer_value(),
                right.into_pointer_value(),
                "ne",
            )
            .map_err(|e| format!("failed to build ptr ne comparison: {e}"))?
    } else {
        return Err("assert_ne: unsupported operand types for comparison".to_string());
    };

    builder
        .build_conditional_branch(ne, pass_block, fail_block)
        .map_err(|e| format!("failed to build assert_ne branch: {e}"))?;

    // Fail block: print diagnostic and abort
    builder.position_at_end(fail_block);
    let abort_fn = module
        .get_function("abort")
        .ok_or_else(|| "missing abort declaration".to_string())?;
    let fmt = builder
        .build_global_string_ptr(
            "assertion failed: expected values to differ\n",
            "assert_ne_fmt",
        )
        .map_err(|e| format!("failed to build assert_ne format string: {e}"))?;
    let puts = module
        .get_function("puts")
        .ok_or_else(|| "missing puts declaration".to_string())?;
    builder
        .build_call(puts, &[fmt.as_pointer_value().into()], "puts_assert_ne")
        .map_err(|e| format!("failed to build assert_ne puts: {e}"))?;
    builder
        .build_call(abort_fn, &[], "abort")
        .map_err(|e| format!("failed to build abort call: {e}"))?;
    builder
        .build_unreachable()
        .map_err(|e| format!("failed to build unreachable: {e}"))?;

    // Pass block: consume owned string arguments after comparison succeeds
    builder.position_at_end(pass_block);
    if both_strings {
        emit_builtin_consume(context, builder, module, left, &MirType::String, left_owned)?;
        emit_builtin_consume(
            context,
            builder,
            module,
            right,
            &MirType::String,
            right_owned,
        )?;
    }
    Ok(())
}

fn build_panic<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    msg: BasicValueEnum<'ctx>,
) -> Result<(), String> {
    let current_block = builder
        .get_insert_block()
        .ok_or_else(|| "missing current insertion block".to_string())?;
    let function = current_block
        .get_parent()
        .ok_or_else(|| "missing parent function for panic".to_string())?;
    let panic_block = context.append_basic_block(function, "panic_block");

    builder
        .build_unconditional_branch(panic_block)
        .map_err(|e| format!("failed to build panic branch: {e}"))?;

    builder.position_at_end(panic_block);

    // Call axon_builtin_panic(msg_ptr, msg_len)
    let panic_fn = module
        .get_function("axon_builtin_panic")
        .ok_or_else(|| "missing axon_builtin_panic declaration".to_string())?;
    let msg_ptr = builder
        .build_extract_value(msg.into_struct_value(), 0, "panic_str_ptr")
        .map_err(|e| format!("failed to extract panic string ptr: {e}"))?;
    let msg_len = builder
        .build_extract_value(msg.into_struct_value(), 1, "panic_str_len")
        .map_err(|e| format!("failed to extract panic string len: {e}"))?;
    builder
        .build_call(
            panic_fn,
            &[msg_ptr.into_pointer_value().into(), msg_len.into()],
            "call_axon_builtin_panic",
        )
        .map_err(|e| format!("failed to build axon_builtin_panic call: {e}"))?;

    let abort = module
        .get_function("abort")
        .ok_or_else(|| "missing abort declaration".to_string())?;
    builder
        .build_call(abort, &[], "abort")
        .map_err(|e| format!("failed to build abort call: {e}"))?;
    builder
        .build_unreachable()
        .map_err(|e| format!("failed to build panic unreachable: {e}"))?;

    Ok(())
}

/// Recursively clean up an aggregate shell's fields.
/// Checks `owned_locals` to determine if the local is still a canonical owner.
/// If not owned (moved/returned/pointer-backed), skips cleanup entirely.
/// For owned shells: walks fields, frees owned string fields, recurses into
/// nested structs, skips pointer-backed fields.
#[allow(clippy::too_many_arguments)]
#[allow(clippy::only_used_in_recursion)]
fn compile_aggregate_shell_cleanup<'ctx>(
    context: &'ctx Context,
    builder: &Builder<'ctx>,
    module: &Module<'ctx>,
    struct_ptr: PointerValue<'ctx>,
    struct_ty: inkwell::types::StructType<'ctx>,
    struct_name: &str,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
    owned_locals: &HashSet<u32>,
    field_modes: &[FieldValueMode],
    struct_literal_fields: &HashMap<u32, HashSet<String>>,
    local_id: LocalId,
) -> Result<(), String> {
    // Get the field information for this struct
    let struct_info = match axon_structs.get(struct_name) {
        Some(info) => info,
        None => {
            // Unknown struct - skip cleanup (might be foreign or builtin)
            return Ok(());
        }
    };

    // For each field, clean it up if it needs cleanup
    for (field_index, (_field_name, field_ty)) in struct_info.fields.iter().enumerate() {
        let field_mode = field_modes
            .get(field_index)
            .unwrap_or(&FieldValueMode::InlineOwned);

        // If this field is a pointer to a canonical owner elsewhere,
        // skip its cleanup -- the owner is responsible.
        if matches!(field_mode, FieldValueMode::PointerToOwner(_)) {
            continue;
        }

        match field_ty {
            MirType::String => {
                // Skip literal string fields - their backing memory is
                // in the read-only segment and must not be freed.
                if let Some(lit_fields) = struct_literal_fields.get(&local_id.0)
                    && lit_fields.contains(_field_name)
                {
                    continue;
                }
                // Extract the string pointer from the field and free it
                let field_ptr = builder
                    .build_struct_gep(
                        struct_ty,
                        struct_ptr,
                        field_index as u32,
                        "cleanup_str_field_ptr",
                    )
                    .map_err(|e| {
                        format!("failed to get string field pointer for cleanup: {e}")
                    })?;
                let string_ty = string_type(context);
                let str_val = builder
                    .build_load(string_ty.as_basic_type_enum(), field_ptr, "str_field_val")
                    .map_err(|e| format!("failed to load string field for cleanup: {e}"))?;
                // String struct is {ptr, len} - extract the ptr field
                let str_data_ptr = builder
                    .build_extract_value(str_val.into_struct_value(), 0, "str_data_ptr")
                    .map_err(|e| {
                        format!("failed to extract string data ptr for cleanup: {e}")
                    })?;
                let free_fn = module
                    .get_function("free")
                    .ok_or_else(|| "missing free declaration".to_string())?;
                builder
                    .build_call(free_fn, &[str_data_ptr.into()], "free_str_field")
                    .map_err(|e| format!("failed to build free call for string field: {e}"))?;
            }
            MirType::Struct(nested_name, _) => {
                // Recursively clean up nested structs (only if still owned)
                let field_ptr = builder
                    .build_struct_gep(
                        struct_ty,
                        struct_ptr,
                        field_index as u32,
                        "cleanup_nested_field_ptr",
                    )
                    .map_err(|e| {
                        format!("failed to get nested field pointer for cleanup: {e}")
                    })?;

                // Build the nested struct's LLVM type from axon_structs info.
                // struct_types is typically empty for nested structs, so we derive it.
                let nested_ty = match basic_type(context, field_ty, axon_structs, struct_types)
                {
                    Ok(BasicTypeEnum::StructType(st)) => st,
                    _ => continue,
                };

                // For nested struct recursion, use a sentinel local ID that
                // won't match any literal field entries. This is conservative:
                // nested literal strings may leak but won't crash.
                let sentinel_local = LocalId(u32::MAX);
                compile_aggregate_shell_cleanup(
                    context,
                    builder,
                    module,
                    field_ptr,
                    nested_ty,
                    nested_name,
                    axon_structs,
                    struct_types,
                    owned_locals,
                    &[],
                    struct_literal_fields,
                    sentinel_local,
                )?;
            }
            // Scalar types, pointer-backed fields, and other types don't need cleanup
            _ => {}
        }
    }

    Ok(())
}

fn basic_metadata_type<'ctx>(
    context: &'ctx Context,
    ty: &MirType,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
) -> Result<BasicMetadataTypeEnum<'ctx>, String> {
    Ok(basic_type(context, ty, axon_structs, struct_types)?.into())
}

fn basic_type<'ctx>(
    context: &'ctx Context,
    ty: &MirType,
    axon_structs: &HashMap<String, AxonStructInfo>,
    struct_types: &HashMap<String, inkwell::types::StructType<'ctx>>,
) -> Result<BasicTypeEnum<'ctx>, String> {
    match ty {
        MirType::Int(width) => Ok(match width {
            IntWidth::I8 | IntWidth::U8 => context.i8_type().into(),
            IntWidth::I16 | IntWidth::U16 => context.i16_type().into(),
            IntWidth::I32 | IntWidth::U32 => context.i32_type().into(),
            IntWidth::I64 | IntWidth::U64 => context.i64_type().into(),
        }),
        MirType::Float(width) => Ok(match width {
            FloatWidth::F32 => context.f32_type().into(),
            FloatWidth::F64 => context.f64_type().into(),
        }),
        MirType::Bool => Ok(context.bool_type().into()),
        MirType::String => Ok(string_type(context).into()),
        MirType::Void | MirType::Unit => {
            Err("void is not a first-class LLVM type".to_string())
        }
        MirType::Struct(name, _) => {
            if let Some(struct_ty) = struct_types.get(name) {
                return Ok(struct_ty.as_basic_type_enum());
            }
            let struct_info = axon_structs
                .get(name)
                .ok_or_else(|| format!("struct '{name}' not found in axon_structs"))?;
            let field_types: Result<Vec<BasicTypeEnum<'ctx>>, String> = struct_info
                .fields
                .iter()
                .map(|(_, field_ty)| basic_type(context, field_ty, axon_structs, struct_types))
                .collect();
            let struct_type = context.struct_type(&field_types?, false);
            Ok(struct_type.into())
        }
        MirType::RawPtr => {
            Ok(context.ptr_type(inkwell::AddressSpace::default()).into())
        }
        MirType::Option(inner) => {
            let payload = basic_type(context, inner, axon_structs, struct_types)?;
            let tag_type = context.bool_type();
            let struct_type = context.struct_type(&[tag_type.into(), payload], false);
            Ok(struct_type.into())
        }
        MirType::Result { ok, err } => {
            let _ok_type = basic_type(context, ok, axon_structs, struct_types)?;
            let _err_type = basic_type(context, err, axon_structs, struct_types)?;
            let tag_type = context.i32_type();
            let payload_size: u32 = 256;
            let payload_type = context.i8_type().array_type(payload_size);
            let struct_type =
                context.struct_type(&[tag_type.into(), payload_type.into()], false);
            Ok(struct_type.into())
        }
        MirType::Tuple(elems) => {
            let field_types: Result<Vec<BasicTypeEnum<'ctx>>, String> = elems
                .iter()
                .map(|e| basic_type(context, e, axon_structs, struct_types))
                .collect();
            let struct_type = context.struct_type(&field_types?, false);
            Ok(struct_type.into())
        }
        MirType::Enum { .. } | MirType::List(_) => Err(
            "enum/list basic type lowering is not yet supported in this codegen path"
                .to_string(),
        ),
    }
}

